﻿import React, { createContext, useCallback, useContext, useEffect, useMemo, useState } from 'react';
import {
  clearAuthSession,
  DEFAULT_AUTH_SETTINGS,
  hashSecret,
  isAuthConfigured,
  loadAuthSession,
  loadAuthSettings,
  saveAuthSession,
  saveAuthSettings,
  verifyPassword,
  verifyPin,
} from '@/lib/auth';
import type { AuthMethod, AuthSettings } from '@/lib/auth';

interface SetupPayload {
  phoneNumber: string;
  password: string;
  pin: string;
  enabledMethods: AuthMethod[];
  googleClientId?: string;
  googleAllowedEmail?: string;
}

interface UpdatePayload {
  phoneNumber?: string;
  password?: string;
  pin?: string;
  enabledMethods?: AuthMethod[];
  googleClientId?: string;
  googleAllowedEmail?: string;
}

interface AuthContextType {
  settings: AuthSettings;
  loading: boolean;
  isAuthenticated: boolean;
  needsSetup: boolean;
  sessionMethod: AuthMethod | null;
  setupAuth: (payload: SetupPayload) => Promise<boolean>;
  updateAuth: (payload: UpdatePayload) => Promise<boolean>;
  loginWithPassword: (phoneNumber: string, password: string) => Promise<boolean>;
  loginWithPin: (pin: string) => Promise<boolean>;
  loginWithGoogle: (email: string) => Promise<boolean>;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | null>(null);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [settings, setSettings] = useState<AuthSettings>(DEFAULT_AUTH_SETTINGS);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [sessionMethod, setSessionMethod] = useState<AuthMethod | null>(null);

  useEffect(() => {
    const nextSettings = loadAuthSettings();
    const nextSession = loadAuthSession();
    setSettings(nextSettings);
    setIsAuthenticated(Boolean(nextSession?.authenticated));
    setSessionMethod(nextSession?.method || null);
    setLoading(false);
  }, []);

  const persistSettings = useCallback((nextSettings: AuthSettings) => {
    setSettings(nextSettings);
    saveAuthSettings(nextSettings);
  }, []);

  const setupAuth = useCallback(async (payload: SetupPayload) => {
    const enabledMethods = payload.enabledMethods.length > 0 ? payload.enabledMethods : ['phone_password'];
    const nextSettings: AuthSettings = {
      phoneNumber: payload.phoneNumber.trim(),
      passwordHash: payload.password ? await hashSecret(payload.password) : '',
      pin: payload.pin.trim(),
      enabledMethods,
      googleClientId: payload.googleClientId?.trim() || '',
      googleAllowedEmail: payload.googleAllowedEmail?.trim() || '',
    };

    if (!isAuthConfigured(nextSettings)) {
      return false;
    }

    persistSettings(nextSettings);
    const method = enabledMethods.includes('phone_password')
      ? 'phone_password'
      : enabledMethods.includes('pin')
      ? 'pin'
      : 'google';
    saveAuthSession(method);
    setIsAuthenticated(true);
    setSessionMethod(method);
    return true;
  }, [persistSettings]);

  const updateAuth = useCallback(async (payload: UpdatePayload) => {
    const enabledMethods = payload.enabledMethods || settings.enabledMethods;
    const nextSettings: AuthSettings = {
      ...settings,
      phoneNumber: payload.phoneNumber !== undefined ? payload.phoneNumber.trim() : settings.phoneNumber,
      pin: payload.pin !== undefined ? payload.pin.trim() : settings.pin,
      enabledMethods,
      googleClientId: payload.googleClientId !== undefined ? payload.googleClientId.trim() : settings.googleClientId,
      googleAllowedEmail: payload.googleAllowedEmail !== undefined ? payload.googleAllowedEmail.trim() : settings.googleAllowedEmail,
      passwordHash: settings.passwordHash,
    };

    if (payload.password !== undefined && payload.password.trim()) {
      nextSettings.passwordHash = await hashSecret(payload.password);
    }

    if (!isAuthConfigured(nextSettings)) {
      return false;
    }

    persistSettings(nextSettings);
    return true;
  }, [persistSettings, settings]);

  const loginWithPassword = useCallback(async (phoneNumber: string, password: string) => {
    const ok = await verifyPassword(phoneNumber, password, settings);
    if (!ok) return false;
    saveAuthSession('phone_password');
    setIsAuthenticated(true);
    setSessionMethod('phone_password');
    return true;
  }, [settings]);

  const loginWithPin = useCallback(async (pin: string) => {
    const ok = verifyPin(pin, settings);
    if (!ok) return false;
    saveAuthSession('pin');
    setIsAuthenticated(true);
    setSessionMethod('pin');
    return true;
  }, [settings]);

  const loginWithGoogle = useCallback(async (email: string) => {
    if (!settings.enabledMethods.includes('google')) return false;
    if (!settings.googleAllowedEmail) return false;
    const ok = settings.googleAllowedEmail.toLowerCase() === email.trim().toLowerCase();
    if (!ok) return false;
    saveAuthSession('google');
    setIsAuthenticated(true);
    setSessionMethod('google');
    return true;
  }, [settings]);

  const logout = useCallback(() => {
    clearAuthSession();
    setIsAuthenticated(false);
    setSessionMethod(null);
  }, []);

  const value = useMemo<AuthContextType>(() => ({
    settings,
    loading,
    isAuthenticated,
    needsSetup: !isAuthConfigured(settings),
    sessionMethod,
    setupAuth,
    updateAuth,
    loginWithPassword,
    loginWithPin,
    loginWithGoogle,
    logout,
  }), [settings, loading, isAuthenticated, sessionMethod, setupAuth, updateAuth, loginWithPassword, loginWithPin, loginWithGoogle, logout]);

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return ctx;
}

import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import { AppData, Customer, Order, Worker, generateId, generateCustomerId, emptyMeasurements } from '@/lib/store';
import { loadDataFromDB, saveDataToDB, performDailyBackup } from '@/lib/db';

interface DataContextType {
  data: AppData;
  loading: boolean;
  addCustomer: (c: Omit<Customer, 'id' | 'customerId' | 'createdAt' | 'measurementHistory'>) => Customer;
  updateCustomer: (id: string, c: Partial<Customer>) => void;
  deleteCustomer: (id: string) => void;
  addOrder: (o: Omit<Order, 'id' | 'createdAt'>) => Order;
  updateOrder: (id: string, o: Partial<Order>) => void;
  deleteOrder: (id: string) => void;
  addWorker: (w: Omit<Worker, 'id' | 'advances' | 'payments' | 'active'>) => Worker;
  updateWorker: (id: string, w: Partial<Worker>) => void;
  deleteWorker: (id: string) => void;
  setData: (d: AppData) => void;
}

const DataContext = createContext<DataContextType | null>(null);

export const DataProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [data, _setData] = useState<AppData>({ customers: [], orders: [], workers: [] });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadDataFromDB().then(d => {
      _setData(d);
      setLoading(false);
      performDailyBackup(d);
    });
  }, []);

  const persist = useCallback((d: AppData) => { _setData(d); saveDataToDB(d); }, []);

  const addCustomer = useCallback((c: Omit<Customer, 'id' | 'customerId' | 'createdAt' | 'measurementHistory'>) => {
    const customer: Customer = {
      ...c,
      id: generateId(),
      customerId: generateCustomerId(data.customers),
      address: c.address || '',
      measurements: c.measurements || emptyMeasurements,
      measurementHistory: [],
      createdAt: new Date().toISOString(),
    };
    const next = { ...data, customers: [...data.customers, customer] };
    persist(next);
    return customer;
  }, [data, persist]);

  const updateCustomer = useCallback((id: string, c: Partial<Customer>) => {
    persist({ ...data, customers: data.customers.map(x => x.id === id ? { ...x, ...c } : x) });
  }, [data, persist]);

  const deleteCustomer = useCallback((id: string) => {
    persist({ ...data, customers: data.customers.filter(x => x.id !== id) });
  }, [data, persist]);

  const addOrder = useCallback((o: Omit<Order, 'id' | 'createdAt'>) => {
    const order: Order = { ...o, id: generateId(), createdAt: new Date().toISOString() };
    persist({ ...data, orders: [...data.orders, order] });
    return order;
  }, [data, persist]);

  const updateOrder = useCallback((id: string, o: Partial<Order>) => {
    persist({ ...data, orders: data.orders.map(x => x.id === id ? { ...x, ...o } : x) });
  }, [data, persist]);

  const deleteOrder = useCallback((id: string) => {
    persist({ ...data, orders: data.orders.filter(x => x.id !== id) });
  }, [data, persist]);

  const addWorker = useCallback((w: Omit<Worker, 'id' | 'advances' | 'payments' | 'active'>) => {
    const worker: Worker = { ...w, id: generateId(), advances: [], payments: [], active: true };
    persist({ ...data, workers: [...data.workers, worker] });
    return worker;
  }, [data, persist]);

  const updateWorker = useCallback((id: string, w: Partial<Worker>) => {
    persist({ ...data, workers: data.workers.map(x => x.id === id ? { ...x, ...w } : x) });
  }, [data, persist]);

  const deleteWorker = useCallback((id: string) => {
    persist({ ...data, workers: data.workers.filter(x => x.id !== id) });
  }, [data, persist]);

  const setData = useCallback((d: AppData) => persist(d), [persist]);

  return (
    <DataContext.Provider value={{
      data, loading, addCustomer, updateCustomer, deleteCustomer,
      addOrder, updateOrder, deleteOrder,
      addWorker, updateWorker, deleteWorker, setData,
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const ctx = useContext(DataContext);
  if (!ctx) throw new Error('useData must be used within DataProvider');
  return ctx;
};

