  const [galleryIdx, setGalleryIdx] = useState(0);
  const [trackId, setTrackId] = useState('');
  const [trackResult, setTrackResult] = useState<any>(null);
  const [orderName, setOrderName] = useState('');
  const [orderPhone, setOrderPhone] = useState('');
  const [orderType, setOrderType] = useState('full_suit');
  const [orderDesign, setOrderDesign] = useState(false);
  const [orderNotes, setOrderNotes] = useState('');
  const [orderSubmitted, setOrderSubmitted] = useState(false);
  const [measName, setMeasName] = useState('');
  const [measPhone, setMeasPhone] = useState('');
  const [measurements, setMeasurements] = useState<Measurements>(emptyMeasurements);
  const [measSubmitted, setMeasSubmitted] = useState(false);

  const whatsAppBase = `https://wa.me/${shop.phone.replace('+', '').replace(/\s/g, '')}`;

  const handleTrack = () => {
    const customer = data.customers.find(c =>
      c.customerId.toLowerCase() === trackId.trim().toLowerCase() || c.phone === trackId.trim()
    );
    if (customer) {
      setTrackResult({ customer, orders: data.orders.filter(o => o.customerId === customer.id) });
    } else {
      setTrackResult({ error: true });
    }
  };

  const handleOrderSubmit = () => {
    const safeName = cleanInput(orderName, 100);
    const safePhone = cleanInput(orderPhone, 20);
    const safeNotes = cleanInput(orderNotes, 500);
    if (!safeName || !safePhone) return;
    let customer = data.customers.find(c => c.phone === safePhone);
    if (!customer) {
      addCustomer({ name: safeName, phone: safePhone, address: '', measurements: emptyMeasurements });
      customer = data.customers[data.customers.length - 1];
    }
    if (customer) {
      addOrder({
        customerId: customer.id, deadline: new Date(Date.now() + 7 * 86400000).toISOString().slice(0, 10),
        totalAmount: 0, advancePaid: 0, paymentStatus: 'pending', notes: `[Online] ${safeNotes}`.trim(), paymentHistory: [],
        suits: [{ id: generateId(), status: 'received', type: orderType as any, designWork: orderDesign, notes: safeNotes, statusHistory: [{ status: 'received' as const, timestamp: new Date().toISOString() }] }],
      });
    }
    setOrderSubmitted(true);
  };

  const handleMeasSubmit = () => {
    const safeName = cleanInput(measName, 100);
    const safePhone = cleanInput(measPhone, 20);
    if (!safeName || !safePhone) return;
    const existing = data.customers.find(c => c.phone === safePhone);
    if (!existing) addCustomer({ name: safeName, phone: safePhone, address: '', measurements });
    setMeasSubmitted(true);
  };

  const sendWhatsAppOrder = () => {
    const typeLabel = orderType === 'full_suit' ? 'Full Suit' : orderType === 'kameez' ? 'Kameez' : 'Shalwar';
    const msg = `Assalam o Alaikum!\n\nName: ${orderName}\nPhone: ${orderPhone}\nType: ${typeLabel}${orderDesign ? ' (design work)' : ''}\nNotes: ${orderNotes || 'None'}`;
    window.open(`${whatsAppBase}?text=${encodeURIComponent(msg)}`, '_blank');
  };

  const sendWhatsAppMeas = () => {
    const m = measurements;
    const msg = `Assalam o Alaikum!\n\nMeasurements:\nName: ${measName}\nPhone: ${measPhone}\n\nKameez: L:${m.kameezLength} Ch:${m.chest} Sh:${m.shoulder} Sl:${m.sleeve} Co:${m.collar} Da:${m.daman}\nShalwar: L:${m.shalwarLength} W:${m.waist} H:${m.hip} P:${m.pancha}\nNotes: ${m.notes || 'None'}`;
    window.open(`${whatsAppBase}?text=${encodeURIComponent(msg)}`, '_blank');
  };

  // TRACK
  if (section === 'track') return (
    <div className="space-y-4 pb-4">
      <button onClick={() => { setSection('home'); setTrackResult(null); setTrackId(''); }} className="flex items-center gap-1 text-sm text-primary font-semibold"><ChevronLeft size={16} /> {isUrdu ? 'واپس' : 'Back'}</button>
      <div className="bg-card rounded-xl p-5 border border-border">
        <h3 className="font-bold text-lg mb-1 flex items-center gap-2"><Search size={18} className="text-primary" /> {t('portal.track')}</h3>
        <p className="text-xs text-muted-foreground mb-4">{isUrdu ? 'اپنا کسٹمر آئی ڈی یا فون نمبر درج کریں' : 'Enter your Customer ID or phone number'}</p>
        <div className="flex gap-2">
          <VoiceInput value={trackId} onChange={setTrackId} placeholder="KT-001 or 0300..." />
          <button onClick={handleTrack} className="px-5 py-3 bg-primary text-primary-foreground rounded-xl font-semibold text-sm touch-target active:scale-95 shrink-0">{isUrdu ? 'تلاش' : 'Track'}</button>
        </div>
        {trackResult && !trackResult.error && (
          <div className="mt-4 space-y-3">
            <div className="bg-primary/5 rounded-xl p-4 border border-primary/20">
              <p className="font-bold">{trackResult.customer.name}</p>
              <p className="text-xs text-muted-foreground font-mono">{trackResult.customer.customerId}</p>
            </div>
            {trackResult.orders.length === 0 ? (
              <p className="text-sm text-muted-foreground text-center py-4">{isUrdu ? 'کوئی آرڈر نہیں' : 'No orders found'}</p>
            ) : trackResult.orders.map((order: any) => {
              const isDelivered = !!order.deliveredAt;
              const balance = order.totalAmount - order.advancePaid;
               return (
                <div key={order.id} className={`rounded-xl p-4 border space-y-3 ${isDelivered ? 'bg-success/5 border-success/20' : 'bg-card border-border'}`}>
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-xs text-muted-foreground">{isUrdu ? 'ڈیلیوری' : 'Delivery'}: {new Date(order.deadline).toLocaleDateString()}</p>
                    </div>
                    {isDelivered && <span className="text-xs font-bold px-2 py-1 rounded-full bg-success text-success-foreground">✅ {isUrdu ? 'حوالے' : 'Delivered'}</span>}
                  </div>
                  {order.suits.map((suit: any, i: number) => {
                    const types: Record<string, string> = { full_suit: isUrdu ? 'فل سوٹ' : 'Full Suit', kameez: isUrdu ? 'قمیض' : 'Kameez', shalwar: isUrdu ? 'شلوار' : 'Shalwar' };
                    const stages = ['received', 'cutting', 'stitching', 'finishing', 'packed', 'ready', 'delivered'];
                    const pct = Math.round(((stages.indexOf(suit.status) + 1) / stages.length) * 100);
                    return (
                      <div key={suit.id} className="bg-background rounded-lg p-3">
                        <div className="flex items-center justify-between mb-2">
                          <span className="text-xs font-medium">{types[suit.type] || suit.type} #{i + 1}</span>
                          <StatusBadge status={suit.status} />
                        </div>
                        <div className="w-full h-2 bg-muted rounded-full overflow-hidden">
                          <div className="h-full bg-primary rounded-full transition-all" style={{ width: `${pct}%` }} />
                        </div>
                        <p className="text-[10px] text-muted-foreground mt-1">{pct}% {isUrdu ? 'مکمل' : 'complete'}</p>
                      </div>
                    );
                  })}
                </div>
              );
            })}
          </div>
        )}
        {trackResult?.error && (
          <div className="mt-4 text-center py-6">
            <p className="text-destructive font-semibold text-sm">{isUrdu ? 'کسٹمر نہیں ملا' : 'Customer not found'}</p>
            <p className="text-xs text-muted-foreground mt-1">{isUrdu ? 'آئی ڈی یا فون چیک کریں' : 'Check your ID or phone'}</p>
          </div>
        )}
      </div>
    </div>
  );

  // ORDER
  if (section === 'order') return (
    <div className="space-y-4 pb-4">
      <button onClick={() => { setSection('home'); setOrderSubmitted(false); }} className="flex items-center gap-1 text-sm text-primary font-semibold"><ChevronLeft size={16} /> {isUrdu ? 'واپس' : 'Back'}</button>
      {orderSubmitted ? (
        <div className="bg-success/5 border border-success/20 rounded-2xl p-8 text-center space-y-3">
          <CheckCircle2 size={48} className="text-success mx-auto" />
          <h3 className="font-bold text-lg">{isUrdu ? 'آرڈر موصول!' : 'Order Received!'}</h3>
          <p className="text-sm text-muted-foreground">{isUrdu ? 'ہم جلد رابطہ کریں گے' : 'We will contact you shortly'}</p>
          <div className="flex gap-3 justify-center pt-2">
            <button onClick={sendWhatsAppOrder} className="px-4 py-2 bg-success text-success-foreground rounded-xl text-sm font-semibold flex items-center gap-2 active:scale-95"><MessageCircle size={16} /> WhatsApp</button>
            <button onClick={() => { setSection('home'); setOrderSubmitted(false); }} className="px-4 py-2 bg-muted rounded-xl text-sm font-semibold active:scale-95">{isUrdu ? 'واپس' : 'Done'}</button>
          </div>
        </div>
      ) : (
        <div className="bg-card rounded-xl p-5 border border-border space-y-4">
          <h3 className="font-bold text-lg flex items-center gap-2"><ShoppingBag size={18} className="text-primary" /> {isUrdu ? 'آن لائن آرڈر' : 'Place Order'}</h3>
          <div><label className="text-xs text-muted-foreground font-medium">{isUrdu ? 'نام' : 'Name'} *</label><VoiceInput value={orderName} onChange={setOrderName} placeholder={isUrdu ? 'آپ کا نام' : 'Your name'} /></div>
          <div><label className="text-xs text-muted-foreground font-medium">{isUrdu ? 'فون' : 'Phone'} *</label><VoiceInput value={orderPhone} onChange={setOrderPhone} type="tel" placeholder="03XX-XXXXXXX" /></div>
          <div>
            <label className="text-xs text-muted-foreground font-medium">{isUrdu ? 'قسم' : 'Type'}</label>
            <select value={orderType} onChange={e => setOrderType(e.target.value)} className="w-full px-4 py-3 rounded-xl bg-background border border-border text-sm focus:outline-none focus:ring-2 focus:ring-primary/30 touch-target">
              <option value="full_suit">{isUrdu ? 'فل سوٹ' : 'Full Suit'}</option>
              <option value="kameez">{isUrdu ? 'صرف قمیض' : 'Kameez Only'}</option>
              <option value="shalwar">{isUrdu ? 'صرف شلوار' : 'Shalwar Only'}</option>
            </select>
          </div>
          <label className="flex items-center gap-2 text-sm">
            <input type="checkbox" checked={orderDesign} onChange={e => setOrderDesign(e.target.checked)} className="rounded" />
            {isUrdu ? 'ڈیزائن ورک' : 'Design Work'}
          </label>
          <div><label className="text-xs text-muted-foreground font-medium">{isUrdu ? 'نوٹس' : 'Notes'}</label><VoiceInput value={orderNotes} onChange={setOrderNotes} multiline rows={3} placeholder={isUrdu ? 'فیبرک، ڈیزائن...' : 'Fabric, design...'} append /></div>
          <div className="flex gap-3 pt-2">
            <button onClick={sendWhatsAppOrder} className="flex-1 py-3 bg-success/10 text-success rounded-xl font-semibold text-sm touch-target active:scale-95 flex items-center justify-center gap-2"><MessageCircle size={16} /> WhatsApp</button>
            <button onClick={handleOrderSubmit} className="flex-1 py-3 bg-primary text-primary-foreground rounded-xl font-semibold text-sm touch-target active:scale-95 flex items-center justify-center gap-2"><Send size={16} /> {isUrdu ? 'آرڈر دیں' : 'Submit'}</button>
          </div>
        </div>
      )}
    </div>
  );

  // MEASUREMENTS
  if (section === 'measurements') return (
    <div className="space-y-4 pb-4">
      <button onClick={() => { setSection('home'); setMeasSubmitted(false); }} className="flex items-center gap-1 text-sm text-primary font-semibold"><ChevronLeft size={16} /> {isUrdu ? 'واپس' : 'Back'}</button>
      {measSubmitted ? (
        <div className="bg-success/5 border border-success/20 rounded-2xl p-8 text-center space-y-3">
          <CheckCircle2 size={48} className="text-success mx-auto" />
          <h3 className="font-bold text-lg">{isUrdu ? 'ناپ موصول!' : 'Measurements Received!'}</h3>
          <button onClick={sendWhatsAppMeas} className="px-4 py-2 bg-success text-success-foreground rounded-xl text-sm font-semibold flex items-center gap-2 active:scale-95 mx-auto"><MessageCircle size={16} /> {isUrdu ? 'واٹس ایپ پر بھیجیں' : 'Also via WhatsApp'}</button>
        </div>
      ) : (
        <div className="bg-card rounded-xl p-5 border border-border space-y-4">
          <h3 className="font-bold text-lg flex items-center gap-2"><Ruler size={18} className="text-primary" /> {isUrdu ? 'ناپ بھیجیں' : 'Send Measurements'}</h3>
          <div><label className="text-xs text-muted-foreground font-medium">{isUrdu ? 'نام' : 'Name'} *</label><VoiceInput value={measName} onChange={setMeasName} /></div>
          <div><label className="text-xs text-muted-foreground font-medium">{isUrdu ? 'فون' : 'Phone'} *</label><VoiceInput value={measPhone} onChange={setMeasPhone} type="tel" placeholder="03XX-XXXXXXX" /></div>
          <div>
            <h4 className="font-semibold text-sm mb-2 text-primary">{isUrdu ? 'قمیض' : 'Kameez'}</h4>
            <div className="grid grid-cols-2 gap-2">
              {kameezFields.map(f => (
                <div key={f.key}><label className="text-[10px] text-muted-foreground">{isUrdu ? f.ur : f.en}</label>
                  <input type="text" inputMode="decimal" value={(measurements as any)[f.key] || ''} onChange={e => setMeasurements({ ...measurements, [f.key]: e.target.value })} className="w-full px-3 py-3 rounded-xl bg-background border border-border text-sm focus:outline-none focus:ring-2 focus:ring-primary/30 touch-target" placeholder="—" />
                </div>
              ))}
            </div>
          </div>
          <div>
            <h4 className="font-semibold text-sm mb-2 text-primary">{isUrdu ? 'شلوار' : 'Shalwar'}</h4>
            <div className="grid grid-cols-2 gap-2">
              {shalwarFields.map(f => (
                <div key={f.key}><label className="text-[10px] text-muted-foreground">{isUrdu ? f.ur : f.en}</label>
                  <input type="text" inputMode="decimal" value={(measurements as any)[f.key] || ''} onChange={e => setMeasurements({ ...measurements, [f.key]: e.target.value })} className="w-full px-3 py-3 rounded-xl bg-background border border-border text-sm focus:outline-none focus:ring-2 focus:ring-primary/30 touch-target" placeholder="—" />
                </div>
              ))}
            </div>
          </div>
          <div><label className="text-xs text-muted-foreground font-medium">{isUrdu ? 'نوٹس' : 'Notes'}</label><VoiceInput value={measurements.notes} onChange={v => setMeasurements({ ...measurements, notes: v })} multiline rows={2} append /></div>
          <div className="flex gap-3 pt-2">
            <button onClick={sendWhatsAppMeas} className="flex-1 py-3 bg-success/10 text-success rounded-xl font-semibold text-sm touch-target active:scale-95 flex items-center justify-center gap-2"><MessageCircle size={16} /> WhatsApp</button>
            <button onClick={handleMeasSubmit} className="flex-1 py-3 bg-primary text-primary-foreground rounded-xl font-semibold text-sm touch-target active:scale-95 flex items-center justify-center gap-2"><Send size={16} /> {isUrdu ? 'بھیجیں' : 'Submit'}</button>
          </div>
        </div>
      )}
    </div>
  );

  // HOME
  return (
    <div className="space-y-5 pb-4">
      {/* Hero */}
      <div className="bg-primary text-primary-foreground rounded-2xl p-6 text-center -mx-4 -mt-4">
        <div className="text-5xl mb-3">✂️</div>
        <h2 className="text-2xl font-bold mb-1">{shop.name}</h2>
        <p className="text-sm opacity-80 mb-1">{shop.tagline}</p>
        <div className="flex items-center justify-center gap-1 text-xs opacity-70 mb-4">
          {Array.from({ length: 5 }).map((_, i) => <Star key={i} size={12} className={i < Math.round(Number(avgRating)) ? 'fill-current' : 'opacity-30'} />)}
          <span className="ml-1">{avgRating}/5 ({reviews.length})</span>
        </div>
        <div className="flex gap-3 justify-center">
          <a href={whatsAppBase} target="_blank" rel="noopener noreferrer" className="px-5 py-2.5 bg-success text-success-foreground rounded-xl text-sm font-semibold flex items-center gap-2 active:scale-95 transition-transform"><MessageCircle size={16} /> WhatsApp</a>
          <a href={`tel:${shop.phone}`} className="px-5 py-2.5 bg-card/20 rounded-xl text-sm font-semibold flex items-center gap-2 active:scale-95 transition-transform"><Phone size={16} /> {isUrdu ? 'کال' : 'Call'}</a>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-3 gap-3">
        <button onClick={() => setSection('track')} className="bg-card rounded-xl p-4 border border-border flex flex-col items-center gap-2 active:scale-[0.98] transition-transform touch-target">
          <div className="p-3 rounded-xl bg-info/10 text-info"><Search size={22} /></div>
          <span className="text-xs font-semibold text-center">{isUrdu ? 'آرڈر ٹریک' : 'Track Order'}</span>
        </button>
        <button onClick={() => setSection('order')} className="bg-card rounded-xl p-4 border border-border flex flex-col items-center gap-2 active:scale-[0.98] transition-transform touch-target">
          <div className="p-3 rounded-xl bg-primary/10 text-primary"><ShoppingBag size={22} /></div>
          <span className="text-xs font-semibold text-center">{isUrdu ? 'آرڈر دیں' : 'Place Order'}</span>
        </button>
        <button onClick={() => setSection('measurements')} className="bg-card rounded-xl p-4 border border-border flex flex-col items-center gap-2 active:scale-[0.98] transition-transform touch-target">
          <div className="p-3 rounded-xl bg-accent/10 text-accent-foreground"><Ruler size={22} /></div>
          <span className="text-xs font-semibold text-center">{isUrdu ? 'ناپ بھیجیں' : 'Measurements'}</span>
        </button>
      </div>

      {/* Gallery */}
      {allDesigns.length > 0 && (
        <div className="bg-card rounded-xl border border-border overflow-hidden">
          <div className="p-4 pb-2 flex items-center justify-between">
            <h3 className="font-bold flex items-center gap-2"><Image size={16} className="text-primary" /> {t('portal.designs')}</h3>
            <div className="flex gap-1">
              <button onClick={() => setGalleryIdx(Math.max(0, galleryIdx - 1))} className="p-1.5 rounded-lg bg-muted text-muted-foreground disabled:opacity-30" disabled={galleryIdx === 0}><ChevronLeft size={16} /></button>
              <button onClick={() => setGalleryIdx(Math.min(allDesigns.length - 1, galleryIdx + 1))} className="p-1.5 rounded-lg bg-muted text-muted-foreground disabled:opacity-30" disabled={galleryIdx === allDesigns.length - 1}><ChevronRight size={16} /></button>
            </div>
          </div>
          <div className="relative">
            <img src={allDesigns[galleryIdx].img} alt={allDesigns[galleryIdx].en} className="w-full h-64 object-cover" loading="lazy" />
            <div className="absolute bottom-0 inset-x-0 bg-gradient-to-t from-black/70 to-transparent p-4">
              <p className="font-bold text-white">{isUrdu ? allDesigns[galleryIdx].ur : allDesigns[galleryIdx].en}</p>
              <p className="text-sm text-white/80">{allDesigns[galleryIdx].price}</p>
            </div>
          </div>
          <div className="flex gap-2 p-3 overflow-x-auto">
            {allDesigns.map((d, i) => (
              <button key={i} onClick={() => setGalleryIdx(i)} className={`shrink-0 w-16 h-16 rounded-lg overflow-hidden border-2 transition-all ${i === galleryIdx ? 'border-primary' : 'border-transparent opacity-60'}`}>
                <img src={d.img} alt={d.en} className="w-full h-full object-cover" loading="lazy" />
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Prices */}
      <div className="bg-card rounded-xl p-4 border border-border">
        <h3 className="font-bold mb-3 flex items-center gap-2"><Scissors size={16} className="text-primary" /> {t('portal.prices')}</h3>
        <div className="space-y-0">
          {shop.prices.map((p, i) => (
            <div key={p.id || i} className="flex items-center justify-between py-3 border-b border-border last:border-0">
              <div>
                <p className="text-sm font-medium">{isUrdu ? p.nameUr : p.nameEn}</p>
                <p className="text-[10px] text-muted-foreground flex items-center gap-1"><Clock size={10} /> {p.duration}</p>
              </div>
              <span className="font-bold text-sm text-primary">{p.price}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Reviews */}
      {reviews.length > 0 && (
        <div className="bg-card rounded-xl p-4 border border-border">
          <h3 className="font-bold mb-3 flex items-center gap-2">
            <Star size={16} className="text-warning" /> {isUrdu ? 'گاہکوں کی رائے' : 'Customer Reviews'}
            <span className="ml-auto text-xs text-muted-foreground font-normal">{avgRating} ⭐ ({reviews.length})</span>
          </h3>
          <div className="space-y-3">
            {reviews.map(r => (
              <div key={r.id} className="bg-background rounded-xl p-4 border border-border">
                <div className="flex items-center gap-2 mb-1.5">
                  <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center text-primary font-bold text-xs">{r.name.charAt(0)}</div>
                  <div className="flex-1">
                    <p className="font-semibold text-sm">{r.name}</p>
                    <div className="flex items-center gap-0.5">
                      {Array.from({ length: 5 }).map((_, i) => (
                        <Star key={i} size={10} className={i < r.rating ? 'text-warning fill-warning' : 'text-muted-foreground'} />
                      ))}
                      <span className="text-[10px] text-muted-foreground ml-1">{r.date}</span>
                    </div>
                  </div>
                </div>
                <p className="text-sm text-muted-foreground">{r.text}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Shop Info & Map */}
      <div className="bg-card rounded-xl p-4 border border-border space-y-3">
        <h3 className="font-bold flex items-center gap-2"><MapPin size={16} className="text-primary" /> {isUrdu ? 'ہماری دکان' : 'Our Shop'}</h3>
        <div className="space-y-1.5 text-sm">
          <p className="flex items-center gap-2 text-muted-foreground"><MapPin size={14} /> {shop.address}</p>
          <p className="flex items-center gap-2 text-muted-foreground"><Phone size={14} /> {shop.phone}</p>
          <p className="flex items-center gap-2 text-muted-foreground"><Clock size={14} /> {shop.hours}</p>
        </div>
        <div className="rounded-xl overflow-hidden border border-border">
          <iframe
            src={`https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3620.4!2d67.03!3d24.86!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x0%3A0x0!2zMjTCsDUxJzM2LjAiTiA2N8KwMDEnNDguMCJF!5e0!3m2!1sen!2s!4v1`}
            width="100%" height="200" style={{ border: 0 }} allowFullScreen loading="lazy" referrerPolicy="no-referrer-when-downgrade" title="Shop Location"
          />
        </div>
        <a href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(shop.address)}`} target="_blank" rel="noopener noreferrer"
          className="inline-flex items-center gap-2 px-4 py-2 bg-primary/10 text-primary rounded-xl text-sm font-semibold active:scale-95 transition-transform">
          📍 {isUrdu ? 'نقشے میں دیکھیں' : 'Open in Maps'}
        </a>
      </div>

      {/* WhatsApp CTA */}
      <a href={whatsAppBase} target="_blank" rel="noopener noreferrer" className="block w-full py-4 bg-success text-success-foreground rounded-xl font-bold text-center text-base active:scale-95 transition-transform">
        <MessageCircle size={20} className="inline mr-2" />
        {isUrdu ? 'واٹس ایپ پر رابطہ کریں' : 'Chat on WhatsApp'}
      </a>
    </div>
  );
}

import { useState } from 'react';
import { useLang } from '@/contexts/LanguageContext';
import { useData } from '@/contexts/DataContext';
import { emptyMeasurements, generateId } from '@/lib/store';
import type { Customer, Measurements, MeasurementRecord } from '@/lib/store';
import { customerSchema, cleanInput } from '@/lib/validation';
import SearchBar from '@/components/SearchBar';
import { Plus, Phone, ChevronRight, X, User, MapPin, History } from 'lucide-react';
import VoiceInput from '@/components/VoiceInput';
import { toast } from 'sonner';

interface MeasurementField {
  key: string;
  label: string;
  options?: { value: string; labelEn: string; labelUr: string }[];
}

const getMeasurementFields = (t: (k: string) => string, isUrdu: boolean): { section: string, items: MeasurementField[] }[] => [
  {
    section: t('measurements.kameez'), items: [
      { key: 'kameezLength', label: t('measurements.length') },
      { key: 'chest', label: t('measurements.chest') },
      { key: 'shoulder', label: t('measurements.shoulder') },
      { key: 'sleeve', label: t('measurements.sleeve') },
      { key: 'kamar', label: t('measurements.kamar') },
      { key: 'daman', label: t('measurements.daman') },
      { key: 'teera', label: t('measurements.teera') },
      { key: 'collar', label: t('measurements.collar') },
      {
        key: 'kameezType', label: isUrdu ? 'کالر اسٹائل' : 'Collar Style', options: [
          { value: 'collar', labelEn: 'Collar', labelUr: 'کالر' },
          { value: 'ban', labelEn: 'Ban', labelUr: 'بین' },
          { value: 'half-ban', labelEn: 'Half Ban', labelUr: 'ہاف بین' },
          { value: 'magzi', labelEn: 'Magzi', labelUr: 'مغزی' },
        ]
      },
      { key: 'cuff', label: t('measurements.cuff') },
      {
        key: 'cuffType', label: isUrdu ? 'کف اسٹائل' : 'Cuff Style', options: [
          { value: 'normal', labelEn: 'Normal', labelUr: 'نارمل' },
          { value: 'cut', labelEn: 'Cut', labelUr: 'کٹ' },
          { value: 'double', labelEn: 'Double', labelUr: 'ڈبل' },
        ]
      },
      { key: 'frontPocket', label: t('measurements.frontPocket') },
      {
        key: 'pocketType', label: isUrdu ? 'جیب اسٹائل' : 'Pocket Style', options: [
          { value: 'front', labelEn: 'Front', labelUr: 'سامنے' },
          { value: 'side', labelEn: 'Side', labelUr: 'سائیڈ' },
          { value: 'both', labelEn: 'Both', labelUr: 'دونوں' },
          { value: 'none', labelEn: 'None', labelUr: 'کوئی نہیں' },
        ]
      },
      {
        key: 'buttonType', label: isUrdu ? 'بٹن' : 'Buttons', options: [
          { value: 'fancy', labelEn: 'Fancy', labelUr: 'فینسی' },
          { value: 'covered', labelEn: 'Covered', labelUr: 'کورڈ' },
          { value: 'simple', labelEn: 'Simple', labelUr: 'سادہ' },
        ]
      },
    ]
  },
  {
    section: t('measurements.shalwar'), items: [
      { key: 'shalwarLength', label: t('measurements.length') },
      { key: 'pancha', label: t('measurements.pancha') },
      { key: 'waist', label: t('measurements.waist') },
      { key: 'hip', label: t('measurements.hip') },
      {
        key: 'bottomType', label: isUrdu ? 'شلوار اسٹائل' : 'Shalwar Style', options: [
          { value: 'simple', labelEn: 'Simple', labelUr: 'سادہ' },
          { value: 'design', labelEn: 'Design', labelUr: 'ڈیزائن' },
          { value: 'heavy', labelEn: 'Heavy', labelUr: 'بھاری' },
        ]
      },
    ]
  },
];

function MeasurementForm({ measurements, onChange, t, isUrdu }: { measurements: Measurements; onChange: (m: Measurements) => void; t: (k: string) => string; isUrdu: boolean }) {
  const fields = getMeasurementFields(t, isUrdu);
  return (
    <div className="space-y-4">
      {fields.map(section => (
        <div key={section.section} className="bg-card/50 rounded-xl p-3 border border-border">
          <h4 className="font-semibold text-sm mb-3 text-primary">{section.section}</h4>
          <div className="grid grid-cols-2 gap-3">
            {section.items.map(item => {
              const val = String((measurements as any)[item.key] || '');

              if (item.options) {
                return (
                  <div key={item.key} className="col-span-2 space-y-1.5 mt-1 border-t border-border/50 pt-3">
                    <label className="text-xs font-semibold text-muted-foreground">{item.label}</label>
                    <div className="flex flex-wrap gap-2">
                      {item.options.map(opt => {
                        const isSelected = val === opt.value;
                        return (
                          <button
                            key={opt.value}
                            type="button"
                            onClick={() => onChange({ ...measurements, [item.key]: isSelected ? '' : opt.value })}
                            className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors touch-target ${isSelected
                              ? 'bg-primary text-primary-foreground shadow-md'
                              : 'bg-muted text-muted-foreground border border-border hover:bg-muted/80'
                              }`}
                          >
                            {isUrdu ? opt.labelUr : opt.labelEn}
                          </button>
                        );
                      })}
                    </div>
                  </div>
                );
              }

              return (
                <div key={item.key}>
                  <label className="text-xs text-muted-foreground">{item.label}</label>
                  <VoiceInput
                    type="text"
                    inputMode="decimal"
                    value={val}
                    onChange={v => onChange({ ...measurements, [item.key]: v })}
                    className="!px-3 !py-3 !rounded-xl !bg-background !border-border text-sm !focus:outline-none !focus:ring-2 !focus:ring-primary/30"
                    placeholder="—"
                  />
                </div>
              );
            })}
          </div>
        </div>
      ))}
      <div className="bg-card/50 rounded-xl p-3 border border-border">
        <label className="text-xs font-semibold mb-2 block">{isUrdu ? 'مزید تفصیلی نوٹس' : 'Detailed Notes'}</label>
        <VoiceInput value={measurements.notes} onChange={v => onChange({ ...measurements, notes: v })} multiline rows={2} append className="!rounded-xl" />
      </div>
    </div>
  );
}

export default function Customers() {
  const { t, isUrdu } = useLang();
  const { data, addCustomer, updateCustomer, deleteCustomer } = useData();
  const [search, setSearch] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [editing, setEditing] = useState<Customer | null>(null);
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [address, setAddress] = useState('');
  const [measurements, setMeasurements] = useState<Measurements>(emptyMeasurements);
  const [showHistory, setShowHistory] = useState<Customer | null>(null);

  const filtered = data.customers.filter(c =>
    c.name.toLowerCase().includes(search.toLowerCase()) ||
    c.customerId.toLowerCase().includes(search.toLowerCase()) ||
    c.phone.includes(search) ||
    (c.address || '').toLowerCase().includes(search.toLowerCase())
  );

  const openNew = () => {
    setEditing(null);
    setName(''); setPhone(''); setAddress('');
    setMeasurements(emptyMeasurements);
    setShowForm(true);
  };

  const openEdit = (c: Customer) => {
    setEditing(c);
    setName(c.name); setPhone(c.phone); setAddress(c.address || '');
    setMeasurements({ ...emptyMeasurements, ...c.measurements });
    setShowForm(true);
  };

  const handleSave = () => {
    const trimmedName = cleanInput(name, 100);
    const trimmedPhone = cleanInput(phone, 20);
    const trimmedAddress = cleanInput(address, 300);

    const validation = customerSchema.safeParse({ name: trimmedName, phone: trimmedPhone, address: trimmedAddress });
    if (!validation.success) {
      const firstError = validation.error.errors[0]?.message || 'Invalid input';
      toast.error(firstError);
      return;
    }

    if (editing) {
      const oldM = editing.measurements;
      const newM = measurements;
      const changed = Object.keys(newM).some(k => (newM as any)[k] !== (oldM as any)[k]);
      let history = editing.measurementHistory || [];
      if (changed && (oldM.chest || oldM.kameezLength)) {
        history = [...history, {
          id: generateId(),
          measurements: { ...oldM },
          date: new Date().toISOString(),
          note: isUrdu ? 'پرانے ناپ' : 'Previous measurements',
        }];
      }
      updateCustomer(editing.id, { name: trimmedName, phone: trimmedPhone, address: trimmedAddress, measurements, measurementHistory: history });
    } else {
      addCustomer({ name: trimmedName, phone: trimmedPhone, address: trimmedAddress, measurements });
    }
    setShowForm(false);
  };

  const orderCount = (cId: string) => data.orders.filter(o => o.customerId === cId).length;

  return (
    <div className="space-y-4 pb-4">
      <SearchBar value={search} onChange={setSearch} />

      <button onClick={openNew} className="w-full py-3 bg-primary text-primary-foreground rounded-xl font-semibold flex items-center justify-center gap-2 touch-target active:scale-[0.98] transition-transform">
        <Plus size={20} /> {t('common.add')} {t('nav.customers')}
      </button>

      <div className="space-y-2">
        {filtered.map(customer => (
          <div key={customer.id} className="premium-card rounded-xl overflow-hidden">
            <div onClick={() => openEdit(customer)} className="p-4 flex items-center gap-3 active:scale-[0.98] transition-transform cursor-pointer">
              <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center shrink-0">
                <User size={18} className="text-primary" />
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <p className="font-semibold text-sm truncate">{customer.name}</p>
                  <span className="text-[10px] px-2 py-0.5 bg-muted rounded-full text-muted-foreground font-mono">{customer.customerId}</span>
                </div>
                <div className="flex items-center gap-2 text-xs text-muted-foreground mt-0.5">
                  <span className="flex items-center gap-1"><Phone size={10} /> {customer.phone || (isUrdu ? 'فون نہیں' : 'No phone')}</span>
                  {customer.address && <span className="flex items-center gap-1"><MapPin size={10} /> {customer.address.slice(0, 20)}{customer.address.length > 20 ? '...' : ''}</span>}
                </div>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-[10px] text-muted-foreground">{orderCount(customer.id)} {isUrdu ? 'آرڈرز' : 'orders'}</span>
                  {(customer.measurementHistory?.length || 0) > 0 && (
                    <span className="text-[10px] text-info">{customer.measurementHistory.length} {isUrdu ? 'ناپ ریکارڈ' : 'measurement records'}</span>
                  )}
                </div>
              </div>
              <ChevronRight size={16} className="text-muted-foreground shrink-0" />
            </div>
            {(customer.measurementHistory?.length || 0) > 0 && (
              <div className="px-4 pb-3">
                <button onClick={() => setShowHistory(customer)} className="flex items-center gap-1 px-2 py-1 rounded-lg bg-info/10 text-info text-[10px] font-semibold active:scale-95 transition-transform">
                  <History size={12} /> {isUrdu ? 'ناپ کی تاریخ' : 'Measurement History'}
                </button>
              </div>
            )}
          </div>
        ))}
        {filtered.length === 0 && (
          <p className="text-center text-muted-foreground py-8 text-sm">{isUrdu ? 'کوئی گاہک نہیں ملا' : 'No customers found'}</p>
        )}
      </div>

      {/* Add/Edit Modal */}
      {showForm && (
        <div className="fixed inset-0 z-50 bg-foreground/40 flex items-end sm:items-center justify-center p-0 sm:p-4" onClick={() => setShowForm(false)}>
          <div className="premium-card w-full max-w-lg rounded-t-2xl sm:rounded-2xl max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
            <div className="flex items-center justify-between p-4 glass-panel sticky top-0 z-10">
              <h2 className="font-bold text-lg">{editing ? t('common.edit') : t('common.add')} {t('nav.customers')}</h2>
              <button onClick={() => setShowForm(false)} className="p-2 touch-target"><X size={20} /></button>
            </div>
            <div className="p-4 space-y-4">
              <div>
                <label className="text-xs text-muted-foreground font-medium">{t('common.name')} *</label>
                <VoiceInput value={name} onChange={setName} />
              </div>
              <div>
                <label className="text-xs text-muted-foreground font-medium">{t('common.phone')}</label>
                <VoiceInput value={phone} onChange={setPhone} type="tel" />
              </div>
              <div>
                <label className="text-xs text-muted-foreground font-medium">{isUrdu ? 'پتہ' : 'Address'}</label>
                <VoiceInput value={address} onChange={setAddress} placeholder={isUrdu ? 'مکمل پتہ...' : 'Full address...'} />
              </div>
              <div>
                <h3 className="font-semibold mb-2">{t('measurements.title')} ({isUrdu ? 'شلوار قمیض' : 'Shalwar Kameez'})</h3>
                <MeasurementForm measurements={measurements} onChange={setMeasurements} t={t} isUrdu={isUrdu} />
              </div>
              <div className="flex gap-3 pt-2">
                {editing && (
                  <button onClick={() => { deleteCustomer(editing.id); setShowForm(false); }} className="flex-1 py-3 rounded-xl border border-destructive text-destructive font-semibold touch-target active:scale-95">
                    {t('common.delete')}
                  </button>
                )}
                <button onClick={handleSave} className="flex-1 py-3 bg-primary text-primary-foreground rounded-xl font-semibold touch-target active:scale-95 transition-transform">
                  {t('common.save')}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Measurement History Modal */}
      {showHistory && (
        <div className="fixed inset-0 z-50 bg-foreground/40 flex items-end sm:items-center justify-center p-0 sm:p-4" onClick={() => setShowHistory(null)}>
          <div className="premium-card w-full max-w-lg rounded-t-2xl sm:rounded-2xl max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
            <div className="flex items-center justify-between p-4 glass-panel sticky top-0 z-10">
              <div>
                <h2 className="font-bold text-lg">{showHistory.name}</h2>
                <p className="text-xs text-muted-foreground">{isUrdu ? 'ناپ کی تاریخ' : 'Measurement History'}</p>
              </div>
              <button onClick={() => setShowHistory(null)} className="p-2 touch-target"><X size={20} /></button>
            </div>
            <div className="p-4 space-y-4">
              {/* Current */}
              <div className="bg-primary/5 border border-primary/20 rounded-xl p-4">
                <h4 className="font-semibold text-sm text-primary mb-2">{isUrdu ? 'موجودہ ناپ' : 'Current Measurements'}</h4>
                <MeasurementDisplay m={showHistory.measurements} isUrdu={isUrdu} />
              </div>
              {/* History */}
              {(showHistory.measurementHistory || []).slice().reverse().map(record => (
                <div key={record.id} className="bg-muted/30 border border-border rounded-xl p-4">
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-xs text-muted-foreground">{new Date(record.date).toLocaleDateString()}</span>
                    <div className="flex items-center gap-2">
                      <span className="text-[10px] text-muted-foreground">{record.note}</span>
                      <button onClick={() => {
                        const updated = (showHistory.measurementHistory || []).filter(r => r.id !== record.id);
                        updateCustomer(showHistory.id, { measurementHistory: updated });
                        setShowHistory({ ...showHistory, measurementHistory: updated });
                      }} className="text-destructive/60 hover:text-destructive p-1 touch-target"><X size={14} /></button>
                    </div>
                  </div>
                  <MeasurementDisplay m={record.measurements} isUrdu={isUrdu} />
                </div>
              ))}
              {(showHistory.measurementHistory || []).length === 0 && (
                <p className="text-center text-muted-foreground py-4 text-sm">{isUrdu ? 'کوئی پرانا ریکارڈ نہیں' : 'No previous records'}</p>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function MeasurementDisplay({ m, isUrdu }: { m: Measurements; isUrdu: boolean }) {
  const items = [
    { label: isUrdu ? 'لمبائی' : 'Length', value: m.kameezLength },
    { label: isUrdu ? 'سینہ' : 'Chest', value: m.chest },
    { label: isUrdu ? 'کندھا' : 'Shoulder', value: m.shoulder },
    { label: isUrdu ? 'آستین' : 'Sleeve', value: m.sleeve },
    { label: isUrdu ? 'کالر' : 'Collar', value: m.collar },
    { label: isUrdu ? 'تیرا' : 'Teera', value: m.teera },
    { label: isUrdu ? 'کمر' : 'Kamar', value: m.kamar },
    { label: isUrdu ? 'دامن' : 'Daman', value: m.daman },
    { label: isUrdu ? 'کف' : 'Cuff', value: m.cuff },
    { label: isUrdu ? 'جیب' : 'Pocket', value: m.frontPocket },
    { label: isUrdu ? 'ٹیگ (قمیض)' : 'Kameez Type', value: m.kameezType },
    { label: isUrdu ? 'اسٹائل (کف)' : 'Cuff Style', value: m.cuffType },
    { label: isUrdu ? 'اسٹائل (جیب)' : 'Pocket Style', value: m.pocketType },
    { label: isUrdu ? 'بٹن' : 'Buttons', value: m.buttonType },
    { label: isUrdu ? 'شلوار' : 'Shalwar', value: m.shalwarLength },
    { label: isUrdu ? 'پونچا' : 'Pooncha', value: m.pancha },
    { label: isUrdu ? 'کمر' : 'Waist', value: m.waist },
    { label: isUrdu ? 'ہپ' : 'Hip', value: m.hip },
    { label: isUrdu ? 'اسٹائل (شلوار)' : 'Bottom Style', value: m.bottomType },
  ].filter(i => i.value);

  if (items.length === 0) return <p className="text-xs text-muted-foreground">{isUrdu ? 'خالی' : 'Empty'}</p>;

  return (
    <div className="grid grid-cols-2 gap-x-2 gap-y-1">
      {items.map(i => (
        <div key={i.label} className="text-[11px] flex justify-between border-b border-border/50 pb-0.5">
          <span className="text-muted-foreground">{i.label}</span>
          <span className="font-semibold text-right">{i.value}</span>
        </div>
      ))}
    </div>
  );
}

import { useMemo } from 'react';
import { useLang } from '@/contexts/LanguageContext';
import { useData } from '@/contexts/DataContext';
import { getDeadlineStatus, getWorkerEarnings, getWorkerSuitsCount } from '@/lib/store';
import { useNavigate } from 'react-router-dom';
import { Users, ClipboardList, Wrench, Ruler, DollarSign, Package, BarChart3, Settings2, Globe, AlertTriangle, Clock, CalendarClock, Timer, Banknote } from 'lucide-react';
import { Progress } from '@/components/ui/progress';

const quickLinks = [
  { path: '/customers', icon: Users, key: 'nav.customers', color: 'bg-primary/10 text-primary' },
  { path: '/orders', icon: ClipboardList, key: 'nav.orders', color: 'bg-info/10 text-info' },
  { path: '/measurements', icon: Ruler, key: 'nav.measurements', color: 'bg-accent/10 text-accent' },
  { path: '/workers', icon: Wrench, key: 'nav.workers', color: 'bg-warning/10 text-warning' },
  { path: '/payments', icon: DollarSign, key: 'nav.payments', color: 'bg-destructive/10 text-destructive' },
  { path: '/ready', icon: Package, key: 'nav.ready', color: 'bg-success/10 text-success' },
  { path: '/reports', icon: BarChart3, key: 'nav.reports', color: 'bg-info/10 text-info' },
  { path: '/portal', icon: Globe, key: 'nav.portal', color: 'bg-primary/10 text-primary' },
  { path: '/settings', icon: Settings2, key: 'nav.settings', color: 'bg-muted text-muted-foreground' },
];

function getDateOnly(d: Date) {
  return new Date(d.getFullYear(), d.getMonth(), d.getDate());
}

export default function Dashboard() {
  const { t, isUrdu } = useLang();
  const { data, loading } = useData();
  const navigate = useNavigate();

  const dashboard = useMemo(() => {
    const now = new Date();
    const todayStart = getDateOnly(now);
    const tomorrowStart = new Date(todayStart.getTime() + 86400000);
    const twoDaysStart = new Date(todayStart.getTime() + 2 * 86400000);
    const threeDaysStart = new Date(todayStart.getTime() + 3 * 86400000);

    const today = now.toISOString().slice(0, 10);
    const todayOrders = data.orders.filter(o => o.createdAt.slice(0, 10) === today);
    const activeOrders = data.orders.filter(o => !o.deliveredAt);

    const overdue: typeof activeOrders = [];
    const dueTomorrow: typeof activeOrders = [];
    const dueNext2Days: typeof activeOrders = [];
    const dueToday: typeof activeOrders = [];

    for (const o of activeOrders) {
      const dl = getDateOnly(new Date(o.deadline));
      if (dl < todayStart) overdue.push(o);
      else if (dl.getTime() === todayStart.getTime()) dueToday.push(o);
      else if (dl.getTime() === tomorrowStart.getTime()) dueTomorrow.push(o);
      else if (dl >= twoDaysStart && dl < threeDaysStart) dueNext2Days.push(o);
    }

    const pendingPayments = data.orders.filter(o => o.paymentStatus !== 'paid' && !o.deliveredAt);
    const totalPending = pendingPayments.reduce((sum, o) => sum + (o.totalAmount - o.advancePaid), 0);
    const readySuits = data.orders.filter(o => !o.deliveredAt && o.suits.some(s => s.status === 'ready' || s.status === 'packed'));

    // Worker activity
    const activeWorkers = data.workers.filter(w => w.active);
    const workerActivity = activeWorkers.map(w => ({
      worker: w,
      weekSuits: getWorkerSuitsCount(w, data.orders, 'weekly'),
      weekEarnings: getWorkerEarnings(w, data.orders, 'weekly'),
    }));

    return {
      todayOrders, activeOrders, overdue, dueToday, dueTomorrow, dueNext2Days,
      pendingPayments, totalPending, readySuits, workerActivity,
    };
  }, [data]);

  if (loading) {
    return <div className="flex items-center justify-center py-20"><div className="animate-pulse-soft text-primary text-lg font-semibold">{isUrdu ? 'لوڈ ہو رہا ہے...' : 'Loading...'}</div></div>;
  }

  const getCustomer = (cid: string) => data.customers.find(c => c.id === cid);

  const OrderRow = ({ order, badge, badgeClass }: { order: any; badge: string; badgeClass: string }) => {
    const customer = getCustomer(order.customerId);
    const suitsDone = order.suits.filter((s: any) => s.status === 'ready' || s.status === 'packed' || s.status === 'delivered').length;
    const progress = order.suits.length > 0 ? Math.round((suitsDone / order.suits.length) * 100) : 0;
    return (
      <div onClick={() => navigate('/orders')} className="flex items-center justify-between bg-card rounded-lg p-3 cursor-pointer active:scale-[0.98] transition-transform border border-border">
        <div className="flex-1 min-w-0">
          <p className="font-medium text-sm truncate">{customer?.name || 'Unknown'}</p>
          <div className="flex items-center gap-2 mt-1">
            <span className="text-[10px] text-muted-foreground">{customer?.customerId}</span>
            <span className="text-[10px] text-muted-foreground">• {order.suits.length} {isUrdu ? 'سوٹ' : 'suits'}</span>
          </div>
          <Progress value={progress} className="h-1.5 mt-1.5" />
        </div>
        <span className={`text-[10px] font-bold px-2 py-1 rounded-full ml-2 whitespace-nowrap ${badgeClass}`}>
          {badge}
        </span>
      </div>
    );
  };

  return (
    <div className="space-y-4 pb-4">
      {/* Stats Row */}
      <div className="grid grid-cols-2 gap-3">
        <button onClick={() => navigate('/orders')} className="bg-card rounded-xl p-4 border border-border text-left active:scale-[0.98] transition-transform">
          <ClipboardList size={16} className="text-primary mb-1" />
          <p className="text-2xl font-bold">{dashboard.todayOrders.length}</p>
          <p className="text-xs text-muted-foreground">{t('dashboard.today')}</p>
        </button>
        <button onClick={() => navigate('/orders')} className="bg-card rounded-xl p-4 border border-border text-left active:scale-[0.98] transition-transform">
          <AlertTriangle size={16} className="text-destructive mb-1" />
          <p className="text-2xl font-bold text-destructive">{dashboard.overdue.length}</p>
          <p className="text-xs text-muted-foreground">{isUrdu ? 'اوور ڈیو' : 'Overdue'}</p>
        </button>
        <button onClick={() => navigate('/payments')} className="bg-card rounded-xl p-4 border border-border text-left active:scale-[0.98] transition-transform">
          <Banknote size={16} className="text-warning mb-1" />
          <p className="text-2xl font-bold">Rs {dashboard.totalPending.toLocaleString()}</p>
          <p className="text-xs text-muted-foreground">{t('dashboard.pending')}</p>
        </button>
        <button onClick={() => navigate('/ready')} className="bg-card rounded-xl p-4 border border-border text-left active:scale-[0.98] transition-transform">
          <Package size={16} className="text-success mb-1" />
          <p className="text-2xl font-bold text-success">{dashboard.readySuits.length}</p>
          <p className="text-xs text-muted-foreground">{isUrdu ? 'تیار سوٹ' : 'Ready Suits'}</p>
        </button>
      </div>

      {/* Overdue Orders */}
      {dashboard.overdue.length > 0 && (
        <div className="bg-destructive/5 border border-destructive/20 rounded-xl p-4">
          <h3 className="font-semibold text-destructive flex items-center gap-2 mb-3 text-sm">
            <AlertTriangle size={16} /> {isUrdu ? '⚠️ اوور ڈیو آرڈرز' : '⚠️ Overdue Orders'}
          </h3>
          <div className="space-y-2">
            {dashboard.overdue.slice(0, 5).map(order => (
              <OrderRow key={order.id} order={order} badge={isUrdu ? 'اوور ڈیو' : 'OVERDUE'} badgeClass="bg-destructive text-destructive-foreground" />
            ))}
            {dashboard.overdue.length > 5 && (
              <p className="text-xs text-muted-foreground text-center pt-1">+{dashboard.overdue.length - 5} {isUrdu ? 'مزید' : 'more'}</p>
            )}
          </div>
        </div>
      )}

      {/* Due Today */}
      {dashboard.dueToday.length > 0 && (
        <div className="bg-warning/5 border border-warning/20 rounded-xl p-4">
          <h3 className="font-semibold text-warning flex items-center gap-2 mb-3 text-sm">
            <Clock size={16} /> {isUrdu ? '🔥 آج ڈیلیوری' : '🔥 Due Today'}
          </h3>
          <div className="space-y-2">
            {dashboard.dueToday.map(order => (
              <OrderRow key={order.id} order={order} badge={isUrdu ? 'آج' : 'TODAY'} badgeClass="bg-warning text-warning-foreground" />
            ))}
          </div>
        </div>
      )}

      {/* Due Tomorrow */}
      {dashboard.dueTomorrow.length > 0 && (
        <div className="bg-info/5 border border-info/20 rounded-xl p-4">
          <h3 className="font-semibold text-info flex items-center gap-2 mb-3 text-sm">
            <CalendarClock size={16} /> {isUrdu ? '📅 کل ڈیلیوری' : '📅 Due Tomorrow'}
          </h3>
          <div className="space-y-2">
            {dashboard.dueTomorrow.map(order => (
              <OrderRow key={order.id} order={order} badge={isUrdu ? 'کل' : 'TOMORROW'} badgeClass="bg-info text-info-foreground" />
            ))}
          </div>
        </div>
      )}

      {/* Approaching (2-3 days) */}
      {dashboard.dueNext2Days.length > 0 && (
        <div className="bg-primary/5 border border-primary/20 rounded-xl p-4">
          <h3 className="font-semibold text-primary flex items-center gap-2 mb-3 text-sm">
            <Timer size={16} /> {isUrdu ? '📋 آنے والے آرڈرز (2-3 دن)' : '📋 Approaching (2-3 Days)'}
          </h3>
          <div className="space-y-2">
            {dashboard.dueNext2Days.map(order => (
              <OrderRow key={order.id} order={order} badge={isUrdu ? '2-3 دن' : '2-3 DAYS'} badgeClass="bg-primary/10 text-primary" />
            ))}
          </div>
        </div>
      )}

      {/* Pending Payments */}
      {dashboard.pendingPayments.length > 0 && (
        <div className="bg-card rounded-xl p-4 border border-border">
          <h3 className="font-semibold text-sm flex items-center gap-2 mb-3">
            <Banknote size={16} className="text-warning" /> {isUrdu ? 'بقایا ادائیگیاں' : 'Pending Payments'}
          </h3>
          <div className="space-y-2">
            {dashboard.pendingPayments.slice(0, 5).map(order => {
              const customer = getCustomer(order.customerId);
              const remaining = order.totalAmount - order.advancePaid;
              return (
                <div key={order.id} onClick={() => navigate('/payments')} className="flex items-center justify-between py-2 border-b border-border last:border-0 cursor-pointer active:scale-[0.98]">
                  <div>
                    <p className="font-medium text-sm">{customer?.name || 'Unknown'}</p>
                    <p className="text-[10px] text-muted-foreground">{customer?.customerId}</p>
                  </div>
                  <p className="text-sm font-bold text-destructive">Rs {remaining.toLocaleString()}</p>
                </div>
              );
            })}
            {dashboard.pendingPayments.length > 5 && (
              <button onClick={() => navigate('/payments')} className="text-xs text-primary font-medium w-full text-center pt-1">
                {isUrdu ? `مزید ${dashboard.pendingPayments.length - 5} دیکھیں` : `View ${dashboard.pendingPayments.length - 5} more →`}
              </button>
            )}
          </div>
        </div>
      )}

      {/* Worker Activity */}
      {dashboard.workerActivity.length > 0 && (
        <div className="bg-card rounded-xl p-4 border border-border">
          <h3 className="font-semibold text-sm flex items-center gap-2 mb-3">
            <Wrench size={16} className="text-warning" /> {isUrdu ? 'کاریگر سرگرمی (ہفتہ)' : 'Worker Activity (Week)'}
          </h3>
          <div className="space-y-2">
            {dashboard.workerActivity.map(({ worker, weekSuits, weekEarnings }) => (
              <div key={worker.id} onClick={() => navigate('/workers')} className="flex items-center justify-between py-2 border-b border-border last:border-0 cursor-pointer active:scale-[0.98]">
                <div>
                  <p className="font-medium text-sm">{worker.name}</p>
                  <p className="text-[10px] text-muted-foreground">{weekSuits} {isUrdu ? 'سوٹ' : 'suits'} {isUrdu ? 'اس ہفتے' : 'this week'}</p>
                </div>
                <p className="text-sm font-bold text-primary">Rs {weekEarnings.toLocaleString()}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Quick Access Grid */}
      <div>
        <h3 className="font-semibold text-sm mb-3 text-muted-foreground">{isUrdu ? 'فوری رسائی' : 'Quick Access'}</h3>
        <div className="grid grid-cols-3 gap-3">
          {quickLinks.map(item => (
            <button
              key={item.path}
              onClick={() => navigate(item.path)}
              className="bg-card rounded-xl p-4 border border-border flex flex-col items-center gap-2 active:scale-[0.98] transition-transform touch-target"
            >
              <div className={`p-3 rounded-xl ${item.color}`}>
                <item.icon size={24} />
              </div>
              <span className="text-xs font-medium text-center">{t(item.key)}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Empty state */}
      {data.orders.length === 0 && data.customers.length === 0 && (
        <div className="text-center py-8">
          <div className="text-5xl mb-4">✂️</div>
          <p className="text-lg font-semibold mb-2">{isUrdu ? 'کراچی ٹیلرز میں خوش آمدید!' : 'Welcome to Karachi Tailors!'}</p>
          <p className="text-sm text-muted-foreground mb-6">{isUrdu ? 'گاہک شامل کر کے شروع کریں' : 'Start by adding customers and creating orders'}</p>
          <button onClick={() => navigate('/customers')} className="px-8 py-4 bg-primary text-primary-foreground rounded-xl font-semibold text-base touch-target active:scale-95 transition-transform">
            {isUrdu ? '+ گاہک شامل کریں' : '+ Add Customer'}
          </button>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { useLang } from '@/contexts/LanguageContext';
import { useData } from '@/contexts/DataContext';
import type { Customer, Measurements as MeasurementsType } from '@/lib/store';
import { generateId } from '@/lib/store';
import SearchBar from '@/components/SearchBar';
import { Ruler, X, User, ChevronRight, History } from 'lucide-react';
import VoiceInput from '@/components/VoiceInput';

interface MeasurementField {
  key: string;
  label: string;
  options?: { value: string; labelEn: string; labelUr: string }[];
}

const getMeasurementFields = (t: (k: string) => string, isUrdu: boolean): { section: string, items: MeasurementField[] }[] => [
  {
    section: t('measurements.kameez'), items: [
      { key: 'kameezLength', label: t('measurements.length') },
      { key: 'chest', label: t('measurements.chest') },
      { key: 'shoulder', label: t('measurements.shoulder') },
      { key: 'sleeve', label: t('measurements.sleeve') },
      { key: 'kamar', label: t('measurements.kamar') },
      { key: 'daman', label: t('measurements.daman') },
      { key: 'teera', label: t('measurements.teera') },
      { key: 'collar', label: t('measurements.collar') },
      {
        key: 'kameezType', label: isUrdu ? 'کالر اسٹائل' : 'Collar Style', options: [
          { value: 'collar', labelEn: 'Collar', labelUr: 'کالر' },
          { value: 'ban', labelEn: 'Ban', labelUr: 'بین' },
          { value: 'half-ban', labelEn: 'Half Ban', labelUr: 'ہاف بین' },
          { value: 'magzi', labelEn: 'Magzi', labelUr: 'مغزی' },
        ]
      },
      { key: 'cuff', label: t('measurements.cuff') },
      {
        key: 'cuffType', label: isUrdu ? 'کف اسٹائل' : 'Cuff Style', options: [
          { value: 'normal', labelEn: 'Normal', labelUr: 'نارمل' },
          { value: 'cut', labelEn: 'Cut', labelUr: 'کٹ' },
          { value: 'double', labelEn: 'Double', labelUr: 'ڈبل' },
        ]
      },
      { key: 'frontPocket', label: t('measurements.frontPocket') },
      {
        key: 'pocketType', label: isUrdu ? 'جیب اسٹائل' : 'Pocket Style', options: [
          { value: 'front', labelEn: 'Front', labelUr: 'سامنے' },
          { value: 'side', labelEn: 'Side', labelUr: 'سائیڈ' },
          { value: 'both', labelEn: 'Both', labelUr: 'دونوں' },
          { value: 'none', labelEn: 'None', labelUr: 'کوئی نہیں' },
        ]
      },
      {
        key: 'buttonType', label: isUrdu ? 'بٹن' : 'Buttons', options: [
          { value: 'fancy', labelEn: 'Fancy', labelUr: 'فینسی' },
          { value: 'covered', labelEn: 'Covered', labelUr: 'کورڈ' },
          { value: 'simple', labelEn: 'Simple', labelUr: 'سادہ' },
        ]
      },
    ]
  },
  {
    section: t('measurements.shalwar'), items: [
      { key: 'shalwarLength', label: t('measurements.length') },
      { key: 'pancha', label: t('measurements.pancha') },
      { key: 'waist', label: t('measurements.waist') },
      { key: 'hip', label: t('measurements.hip') },
      {
        key: 'bottomType', label: isUrdu ? 'شلوار اسٹائل' : 'Shalwar Style', options: [
          { value: 'simple', labelEn: 'Simple', labelUr: 'سادہ' },
          { value: 'design', labelEn: 'Design', labelUr: 'ڈیزائن' },
          { value: 'heavy', labelEn: 'Heavy', labelUr: 'بھاری' },
        ]
      },
    ]
  },
];

export default function Measurements() {
  const { t, isUrdu } = useLang();
  const { data, updateCustomer } = useData();
  const [search, setSearch] = useState('');
  const [editing, setEditing] = useState<Customer | null>(null);
  const [measurements, setMeasurements] = useState<MeasurementsType | null>(null);
  const [showHistory, setShowHistory] = useState<Customer | null>(null);

  const filtered = data.customers.filter(c =>
    c.name.toLowerCase().includes(search.toLowerCase()) ||
    c.customerId.toLowerCase().includes(search.toLowerCase()) ||
    c.phone.includes(search)
  );

  const openEdit = (c: Customer) => {
    setEditing(c);
    setMeasurements({ ...c.measurements });
  };

  const handleSave = () => {
    if (!editing || !measurements) return;
    // Save old measurements to history
    const oldM = editing.measurements;
    let history = editing.measurementHistory || [];
    const hasOld = oldM.chest || oldM.kameezLength || oldM.shoulder || oldM.waist;
    const changed = Object.keys(measurements).some(k => (measurements as any)[k] !== (oldM as any)[k]);
    if (hasOld && changed) {
      history = [...history, {
        id: generateId(),
        measurements: { ...oldM },
        date: new Date().toISOString(),
        note: isUrdu ? 'پرانے ناپ' : 'Previous measurements',
      }];
    }
    updateCustomer(editing.id, { measurements, measurementHistory: history });
    setEditing(null);
  };

  const fields = getMeasurementFields(t, isUrdu);

  const hasMeasurements = (c: Customer) => {
    const m = c.measurements;
    return m && (m.chest || m.kameezLength || m.shoulder || m.waist);
  };

  return (
    <div className="space-y-4 pb-4">
      <div className="flex items-center gap-2 mb-1">
        <Ruler size={22} className="text-primary" />
        <h2 className="text-lg font-bold">{t('measurements.title')}</h2>
      </div>

      <SearchBar value={search} onChange={setSearch} />

      <div className="space-y-2">
        {filtered.map(customer => (
          <div key={customer.id} className="bg-card rounded-xl border border-border overflow-hidden">
            <div onClick={() => openEdit(customer)} className="p-4 flex items-center gap-3 active:scale-[0.98] transition-transform cursor-pointer">
              <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center shrink-0">
                <User size={18} className="text-primary" />
              </div>
              <div className="flex-1 min-w-0">
                <p className="font-semibold text-sm truncate">{customer.name}</p>
                <p className="text-xs text-muted-foreground font-mono">{customer.customerId}</p>
              </div>
              <div className="flex items-center gap-2">
                {hasMeasurements(customer) ? (
                  <span className="text-[10px] px-2 py-1 rounded-full bg-success/10 text-success font-semibold">✓ {isUrdu ? 'ناپ موجود' : 'Measured'}</span>
                ) : (
                  <span className="text-[10px] px-2 py-1 rounded-full bg-warning/10 text-warning font-semibold">{isUrdu ? 'ناپ نہیں' : 'No measurements'}</span>
                )}
                <ChevronRight size={16} className="text-muted-foreground shrink-0" />
              </div>
            </div>
            {(customer.measurementHistory?.length || 0) > 0 && (
              <div className="px-4 pb-3">
                <button onClick={() => setShowHistory(customer)} className="flex items-center gap-1 px-2 py-1 rounded-lg bg-info/10 text-info text-[10px] font-semibold active:scale-95 transition-transform">
                  <History size={12} /> {customer.measurementHistory.length} {isUrdu ? 'پرانے ریکارڈ' : 'previous records'}
                </button>
              </div>
            )}
          </div>
        ))}
        {filtered.length === 0 && <p className="text-center text-muted-foreground py-8 text-sm">{isUrdu ? 'کوئی گاہک نہیں ملا' : 'No customers found'}</p>}
      </div>

      {/* Edit Modal */}
      {editing && measurements && (
        <div className="fixed inset-0 z-50 bg-foreground/40 flex items-end sm:items-center justify-center" onClick={() => setEditing(null)}>
          <div className="bg-card w-full max-w-lg rounded-t-2xl sm:rounded-2xl max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
            <div className="flex items-center justify-between p-4 border-b border-border sticky top-0 bg-card z-10">
              <div>
                <h2 className="font-bold text-lg">{editing.name}</h2>
                <p className="text-xs text-muted-foreground">{editing.customerId} · {t('measurements.title')}</p>
              </div>
              <button onClick={() => setEditing(null)} className="p-2 touch-target"><X size={20} /></button>
            </div>
            <div className="p-4 space-y-4">
              {fields.map(section => (
                <div key={section.section} className="bg-card/50 rounded-xl p-3 border border-border">
                  <h4 className="font-semibold text-sm mb-3 text-primary">{section.section}</h4>
                  <div className="grid grid-cols-2 gap-3">
                    {section.items.map(item => {
                      const val = String((measurements as any)[item.key] || '');

                      if (item.options) {
                        return (
                          <div key={item.key} className="col-span-2 space-y-1.5 mt-1 border-t border-border/50 pt-3">
                            <label className="text-xs font-semibold text-muted-foreground">{item.label}</label>
                            <div className="flex flex-wrap gap-2">
                              {item.options.map(opt => {
                                const isSelected = val === opt.value;
                                return (
                                  <button
                                    key={opt.value}
                                    type="button"
                                    onClick={() => setMeasurements({ ...measurements, [item.key]: isSelected ? '' : opt.value })}
                                    className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors touch-target ${isSelected
                                      ? 'bg-primary text-primary-foreground shadow-md'
                                      : 'bg-muted text-muted-foreground border border-border hover:bg-muted/80'
                                      }`}
                                  >
                                    {isUrdu ? opt.labelUr : opt.labelEn}
                                  </button>
                                );
                              })}
                            </div>
                          </div>
                        );
                      }

                      return (
                        <div key={item.key}>
                          <label className="text-xs text-muted-foreground">{item.label}</label>
                          <VoiceInput
                            type="text"
                            inputMode="decimal"
                            value={val}
                            onChange={v => setMeasurements({ ...measurements, [item.key]: v })}
                            className="!px-3 !py-3 !rounded-xl !bg-background !border-border text-sm !focus:outline-none !focus:ring-2 !focus:ring-primary/30"
                            placeholder="—"
                          />
                        </div>
                      );
                    })}
                  </div>
                </div>
              ))}
              <div className="bg-card/50 rounded-xl p-3 border border-border">
                <label className="text-xs font-semibold mb-2 block">{isUrdu ? 'مزید تفصیلی نوٹس' : 'Detailed Notes'}</label>
                <VoiceInput
                  value={measurements.notes}
                  onChange={v => setMeasurements({ ...measurements, notes: v })}
                  className="!rounded-xl"
                  multiline rows={3} append
                />
              </div>
              <button onClick={handleSave} className="w-full py-4 bg-primary text-primary-foreground rounded-xl font-semibold text-base touch-target active:scale-95 transition-transform">
                {t('common.save')}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* History Modal */}
      {showHistory && (
        <div className="fixed inset-0 z-50 bg-foreground/40 flex items-end sm:items-center justify-center" onClick={() => setShowHistory(null)}>
          <div className="bg-card w-full max-w-lg rounded-t-2xl sm:rounded-2xl max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
            <div className="flex items-center justify-between p-4 border-b border-border sticky top-0 bg-card z-10">
              <div>
                <h2 className="font-bold text-lg">{showHistory.name}</h2>
                <p className="text-xs text-muted-foreground">{isUrdu ? 'ناپ کی تاریخ' : 'Measurement History'}</p>
              </div>
              <button onClick={() => setShowHistory(null)} className="p-2 touch-target"><X size={20} /></button>
            </div>
            <div className="p-4 space-y-3">
              <div className="bg-primary/5 border border-primary/20 rounded-xl p-3">
                <h4 className="text-xs font-semibold text-primary mb-2">{isUrdu ? 'موجودہ' : 'Current'}</h4>
                <MeasurementGrid m={showHistory.measurements} isUrdu={isUrdu} />
              </div>
              {(showHistory.measurementHistory || []).slice().reverse().map(r => (
                <div key={r.id} className="bg-muted/30 border border-border rounded-xl p-3">
                  <p className="text-[10px] text-muted-foreground mb-2">{new Date(r.date).toLocaleDateString()} · {r.note}</p>
                  <MeasurementGrid m={r.measurements} isUrdu={isUrdu} />
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function MeasurementGrid({ m, isUrdu }: { m: any; isUrdu: boolean }) {
  const items = [
    { label: isUrdu ? 'لمبائی' : 'Length', value: m.kameezLength },
    { label: isUrdu ? 'سینہ' : 'Chest', value: m.chest },
    { label: isUrdu ? 'کندھا' : 'Shoulder', value: m.shoulder },
    { label: isUrdu ? 'آستین' : 'Sleeve', value: m.sleeve },
    { label: isUrdu ? 'کالر' : 'Collar', value: m.collar },
    { label: isUrdu ? 'تیرا' : 'Teera', value: m.teera },
    { label: isUrdu ? 'کمر' : 'Kamar', value: m.kamar },
    { label: isUrdu ? 'شلوار' : 'Shalwar', value: m.shalwarLength },
    { label: isUrdu ? 'پونچا' : 'Pooncha', value: m.pancha },
  ].filter(i => i.value);

  if (items.length === 0) return <p className="text-xs text-muted-foreground">{isUrdu ? 'خالی' : 'Empty'}</p>;
  return (
    <div className="grid grid-cols-3 gap-1">
      {items.map(i => (
        <div key={i.label} className="text-xs"><span className="text-muted-foreground">{i.label}: </span><span className="font-semibold">{i.value}</span></div>
      ))}
    </div>
  );
}

import { useState, useMemo } from 'react';
import { useLang } from '@/contexts/LanguageContext';
import { useData } from '@/contexts/DataContext';
import { getDeadlineStatus, generateId } from '@/lib/store';
import type { Order, OrderSuit, SuitStatus, StatusChange, SuitLocation } from '@/lib/store';
import { getWhatsAppLink, getDeadlineReminderMessage, getReadyForPickupMessage, getPaymentReminderMessage } from '@/lib/notifications';
import { printReceipt, getReceiptWhatsAppLink } from '@/lib/printReceipt';
import SearchBar from '@/components/SearchBar';
import StatusBadge from '@/components/StatusBadge';
import { Plus, X, MessageCircle, Printer, Clock, Filter, MapPin } from 'lucide-react';
import VoiceInput from '@/components/VoiceInput';

const ALL_STATUSES: SuitStatus[] = ['received', 'cutting', 'stitching', 'finishing', 'packed', 'ready', 'delivered'];

function nextStatus(s: SuitStatus): SuitStatus {
  const i = ALL_STATUSES.indexOf(s);
  return ALL_STATUSES[Math.min(i + 1, ALL_STATUSES.length - 1)];
}

const statusEmoji: Record<SuitStatus, string> = {
  received: '📥', cutting: '✂️', stitching: '🧵', finishing: '✨', packed: '📦', ready: '✅', delivered: '🤝',
};

function SuitTimeline({ suit, t, isUrdu }: { suit: OrderSuit; t: (k: string) => string; isUrdu: boolean }) {
  const history = suit.statusHistory || [];
  if (history.length === 0) return null;

  return (
    <div className="space-y-1 py-2">
      {history.map((h, i) => {
        const isLast = i === history.length - 1;
        return (
          <div key={i} className="flex items-start gap-2">
            <div className="flex flex-col items-center">
              <div className={`w-6 h-6 rounded-full flex items-center justify-center text-xs ${isLast ? 'bg-primary text-primary-foreground' : 'bg-muted text-muted-foreground'}`}>
                {statusEmoji[h.status]}
              </div>
              {i < history.length - 1 && <div className="w-0.5 h-4 bg-border" />}
            </div>
            <div className="flex-1 min-w-0 pb-1">
              <p className={`text-xs font-semibold ${isLast ? 'text-primary' : 'text-foreground'}`}>{t(`status.${h.status}`)}</p>
              <p className="text-[10px] text-muted-foreground">{new Date(h.timestamp).toLocaleString()}</p>
            </div>
          </div>
        );
      })}
    </div>
  );
}

export default function Orders() {
  const { t, lang, isUrdu } = useLang();
  const { data, addOrder, updateOrder, deleteOrder } = useData();
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState<'all' | 'active' | 'delivered' | 'overdue'>('all');
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);
  const [showTimeline, setShowTimeline] = useState<Order | null>(null);

  // Form state
  const [customerId, setCustomerId] = useState('');
  const [deadline, setDeadline] = useState('');
  const [totalAmount, setTotalAmount] = useState('');
  const [advancePaid, setAdvancePaid] = useState('');
  const [suits, setSuits] = useState<OrderSuit[]>([]);
  const [notes, setNotes] = useState('');

  const filtered = data.orders.filter(o => {
    const customer = data.customers.find(c => c.id === o.customerId);
    if (!customer) return false;
    const q = search.toLowerCase();
    if (q && !(customer.name.toLowerCase().includes(q) || customer.customerId.toLowerCase().includes(q) || customer.phone.includes(q))) return false;

    // Status filter
    if (statusFilter === 'active' && o.deliveredAt) return false;
    if (statusFilter === 'delivered' && !o.deliveredAt) return false;
    if (statusFilter === 'overdue' && getDeadlineStatus(o.deadline) !== 'overdue') return false;

    // Date range filter
    if (dateFrom && new Date(o.createdAt) < new Date(dateFrom)) return false;
    if (dateTo && new Date(o.createdAt) > new Date(dateTo + 'T23:59:59')) return false;

    return true;
  }).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

  const openNew = () => {
    setEditingOrder(null);
    setCustomerId(data.customers[0]?.id || '');
    setDeadline(new Date(Date.now() + 7 * 86400000).toISOString().slice(0, 10));
    setTotalAmount('');
    setAdvancePaid('');
    setNotes('');
    setSuits([{
      id: generateId(), status: 'received', type: 'full_suit', designWork: false, notes: '',
      statusHistory: [{ status: 'received', timestamp: new Date().toISOString() }],
      workers: {},
    }]);
    setShowForm(true);
  };

  const openEdit = (o: Order) => {
    setEditingOrder(o);
    setCustomerId(o.customerId);
    setDeadline(o.deadline.slice(0, 10));
    setTotalAmount(String(o.totalAmount));
    setAdvancePaid(String(o.advancePaid));
    setNotes(o.notes || '');
    setSuits([...o.suits]);
    setShowForm(true);
  };

  const addSuit = () => {
    setSuits([...suits, {
      id: generateId(), status: 'received', type: 'full_suit', designWork: false, notes: '',
      statusHistory: [{ status: 'received', timestamp: new Date().toISOString() }],
      workers: {},
    }]);
  };

  const updateSuit = (idx: number, patch: Partial<OrderSuit>) => {
    setSuits(suits.map((s, i) => i === idx ? { ...s, ...patch } : s));
  };

  const removeSuit = (idx: number) => {
    if (suits.length > 1) setSuits(suits.filter((_, i) => i !== idx));
  };

  const handleSave = () => {
    if (!customerId || !deadline) return;
    const total = Number(totalAmount) || 0;
    const advance = Number(advancePaid) || 0;
    const paymentStatus = advance >= total ? 'paid' : advance > 0 ? 'advance' : 'pending';

    if (editingOrder) {
      updateOrder(editingOrder.id, { customerId, deadline, totalAmount: total, advancePaid: advance, paymentStatus: paymentStatus as any, suits, notes });
    } else {
      addOrder({ customerId, deadline, totalAmount: total, advancePaid: advance, paymentStatus: paymentStatus as any, suits, notes, paymentHistory: advance > 0 ? [{ id: Date.now().toString(36), amount: advance, date: new Date().toISOString(), method: 'cash' as const, note: isUrdu ? 'پیشگی' : 'Advance' }] : [] });
    }
    setShowForm(false);
  };

  const cycleSuitStatus = (orderId: string, suitId: string) => {
    const order = data.orders.find(o => o.id === orderId);
    if (!order) return;
    const now = new Date().toISOString();
    const newSuits = order.suits.map(s => {
      if (s.id !== suitId) return s;
      const newStatus = nextStatus(s.status);
      const history: StatusChange[] = [...(s.statusHistory || []), { status: newStatus, timestamp: now }];
      return { ...s, status: newStatus, workerId: s.workers?.[newStatus], statusHistory: history };
    });
    const allDelivered = newSuits.every(s => s.status === 'delivered');
    updateOrder(orderId, { suits: newSuits, deliveredAt: allDelivered ? now : undefined });
  };

  const handlePrint = (order: Order) => {
    const customer = data.customers.find(c => c.id === order.customerId);
    if (!customer) return;
    printReceipt({ order, customer, lang });
  };

  return (
    <div className="space-y-4 pb-4">
      <SearchBar value={search} onChange={setSearch} />

      {/* Filters */}
      <div className="space-y-2">
        <div className="flex gap-2 overflow-x-auto pb-1">
          {([['all', isUrdu ? 'سب' : 'All'], ['active', isUrdu ? 'فعال' : 'Active'], ['delivered', isUrdu ? 'مکمل' : 'Delivered'], ['overdue', isUrdu ? 'تاخیر' : 'Overdue']] as const).map(([key, label]) => (
            <button key={key} onClick={() => setStatusFilter(key)}
              className={`px-3 py-1.5 rounded-full text-xs font-semibold whitespace-nowrap transition-colors ${statusFilter === key ? 'bg-primary text-primary-foreground' : 'bg-muted text-muted-foreground'}`}>
              {label}
              {key !== 'all' && <span className="ml-1 opacity-70">
                ({key === 'active' ? data.orders.filter(o => !o.deliveredAt).length : key === 'delivered' ? data.orders.filter(o => o.deliveredAt).length : data.orders.filter(o => getDeadlineStatus(o.deadline) === 'overdue').length})
              </span>}
            </button>
          ))}
        </div>
        <div className="flex gap-2">
          <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} placeholder={isUrdu ? 'سے' : 'From'}
            className="flex-1 px-3 py-2 rounded-lg bg-background border border-border text-xs focus:outline-none focus:ring-2 focus:ring-primary/30" />
          <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} placeholder={isUrdu ? 'تک' : 'To'}
            className="flex-1 px-3 py-2 rounded-lg bg-background border border-border text-xs focus:outline-none focus:ring-2 focus:ring-primary/30" />
          {(dateFrom || dateTo) && (
            <button onClick={() => { setDateFrom(''); setDateTo(''); }} className="px-2 py-2 rounded-lg bg-muted text-muted-foreground text-xs">
              <X size={14} />
            </button>
          )}
        </div>
      </div>

      <button onClick={openNew} className="w-full py-3 bg-primary text-primary-foreground rounded-xl font-semibold flex items-center justify-center gap-2 touch-target active:scale-[0.98] transition-transform">
        <Plus size={20} /> {t('order.new')}
      </button>

      <div className="space-y-3">
        {filtered.map(order => {
          const customer = data.customers.find(c => c.id === order.customerId);
          const dlStatus = getDeadlineStatus(order.deadline);
          const balance = order.totalAmount - order.advancePaid;
          const daysLeft = Math.ceil((new Date(order.deadline).getTime() - Date.now()) / 86400000);

          return (
            <div key={order.id} className="premium-card rounded-xl border border-white/5 overflow-hidden">
              <div className="p-4" onClick={() => openEdit(order)}>
                <div className="flex items-start justify-between mb-2">
                  <div>
                    <p className="font-semibold">{customer?.name || 'Unknown'}</p>
                    <p className="text-xs text-muted-foreground font-mono">{customer?.customerId}</p>
                  </div>
                  <div className="text-right space-y-1">
                    <span className={`text-xs font-bold px-2 py-1 rounded-full ${dlStatus === 'overdue' ? 'bg-destructive text-destructive-foreground' :
                        dlStatus === 'urgent' ? 'bg-warning text-warning-foreground' :
                          dlStatus === 'approaching' ? 'bg-accent text-accent-foreground' :
                            'bg-muted text-muted-foreground'
                      }`}>
                      {new Date(order.deadline).toLocaleDateString()}
                    </span>
                    <p className={`text-[10px] font-semibold ${daysLeft < 0 ? 'text-destructive' : daysLeft <= 1 ? 'text-warning' : 'text-muted-foreground'}`}>
                      {daysLeft < 0 ? (isUrdu ? `${Math.abs(daysLeft)} دن گزر گئے` : `${Math.abs(daysLeft)}d overdue`) : daysLeft === 0 ? (isUrdu ? 'آج' : 'Today') : (isUrdu ? `${daysLeft} دن باقی` : `${daysLeft}d left`)}
                    </p>
                  </div>
                </div>
                <div className="flex items-center gap-3 text-xs text-muted-foreground">
                  <span>{order.suits.length} {t('order.suits')}</span>
                  <span>Rs {order.totalAmount.toLocaleString()}</span>
                  {balance > 0 && <span className="text-destructive font-semibold">{isUrdu ? 'بقایا' : 'Due'}: Rs {balance.toLocaleString()}</span>}
                </div>
                {order.notes && <p className="text-[10px] text-muted-foreground mt-1 line-clamp-1">📝 {order.notes}</p>}
              </div>
              <div className="px-4 pb-3 space-y-2">
                <div className="flex flex-wrap gap-2">
                  {order.suits.map((suit, i) => (
                    <div key={suit.id} className="flex flex-col gap-0.5">
                      <div className="flex items-center gap-1">
                        <span className="text-[10px] text-muted-foreground">#{i + 1}</span>
                        <StatusBadge status={suit.status} onClick={() => cycleSuitStatus(order.id, suit.id)} />
                      </div>
                      {suit.location && (suit.location.box || suit.location.line || suit.location.khanna) && (
                        <div className="flex items-center gap-1 text-[9px] text-muted-foreground ml-3">
                          <MapPin size={8} />
                          {suit.location.box && <span>{isUrdu ? 'باکس' : 'Box'}: {suit.location.box}</span>}
                          {suit.location.line && <span>{isUrdu ? 'لائن' : 'Line'}: {suit.location.line}</span>}
                          {suit.location.khanna && <span>{isUrdu ? 'خانہ' : 'Khanna'}: {suit.location.khanna}</span>}
                        </div>
                      )}
                    </div>
                  ))}
                </div>
                <div className="flex gap-2 flex-wrap">
                  {/* Print Receipt */}
                  <button onClick={() => handlePrint(order)} className="flex items-center gap-1 px-2 py-1 rounded-lg bg-primary/10 text-primary text-[10px] font-semibold active:scale-95 transition-transform">
                    <Printer size={12} /> {isUrdu ? 'پرنٹ' : 'Print'}
                  </button>
                  {/* WhatsApp Receipt */}
                  {customer?.phone && (
                    <a href={getReceiptWhatsAppLink({ order, customer, lang })} target="_blank" rel="noopener noreferrer"
                      className="flex items-center gap-1 px-2 py-1 rounded-lg bg-success/10 text-success text-[10px] font-semibold active:scale-95 transition-transform">
                      <MessageCircle size={12} /> {isUrdu ? 'رسید بھیجیں' : 'Send Receipt'}
                    </a>
                  )}
                  {/* Timeline */}
                  <button onClick={() => setShowTimeline(order)} className="flex items-center gap-1 px-2 py-1 rounded-lg bg-info/10 text-info text-[10px] font-semibold active:scale-95 transition-transform">
                    <Clock size={12} /> {isUrdu ? 'ٹائم لائن' : 'Timeline'}
                  </button>
                  {customer?.phone && (
                    <>
                      {(dlStatus === 'overdue' || dlStatus === 'urgent' || dlStatus === 'approaching') && (
                        <a href={getWhatsAppLink(customer.phone, getDeadlineReminderMessage(customer.name, order.deadline, lang))} target="_blank" rel="noopener noreferrer"
                          className="flex items-center gap-1 px-2 py-1 rounded-lg bg-success/10 text-success text-[10px] font-semibold active:scale-95 transition-transform">
                          <MessageCircle size={12} /> {isUrdu ? 'یاد دہانی' : 'Reminder'}
                        </a>
                      )}
                      {order.suits.every(s => s.status === 'ready' || s.status === 'delivered') && !order.deliveredAt && (
                        <a href={getWhatsAppLink(customer.phone, getReadyForPickupMessage(customer.name, lang))} target="_blank" rel="noopener noreferrer"
                          className="flex items-center gap-1 px-2 py-1 rounded-lg bg-success/10 text-success text-[10px] font-semibold active:scale-95 transition-transform">
                          <MessageCircle size={12} /> {isUrdu ? 'تیار پیغام' : 'Ready Msg'}
                        </a>
                      )}
                      {balance > 0 && (
                        <a href={getWhatsAppLink(customer.phone, getPaymentReminderMessage(customer.name, balance, lang))} target="_blank" rel="noopener noreferrer"
                          className="flex items-center gap-1 px-2 py-1 rounded-lg bg-warning/10 text-warning text-[10px] font-semibold active:scale-95 transition-transform">
                          <MessageCircle size={12} /> {isUrdu ? 'بقایا' : 'Payment'}
                        </a>
                      )}
                    </>
                  )}
                </div>
              </div>
            </div>
          );
        })}
        {filtered.length === 0 && <p className="text-center text-muted-foreground py-8 text-sm">{isUrdu ? 'کوئی آرڈر نہیں' : 'No orders found'}</p>}
      </div>

      {/* Timeline Modal */}
      {showTimeline && (
        <div className="fixed inset-0 z-50 bg-foreground/40 flex items-end sm:items-center justify-center" onClick={() => setShowTimeline(null)}>
          <div className="premium-card w-full max-w-lg rounded-t-2xl sm:rounded-2xl max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
            <div className="flex items-center justify-between p-4 border-b border-border sticky top-0 bg-card z-10">
              <div>
                <h2 className="font-bold text-lg">{isUrdu ? 'آرڈر ٹائم لائن' : 'Order Timeline'}</h2>
                <p className="text-xs text-muted-foreground">{data.customers.find(c => c.id === showTimeline.customerId)?.name}</p>
              </div>
              <button onClick={() => setShowTimeline(null)} className="p-2 touch-target"><X size={20} /></button>
            </div>
            <div className="p-4 space-y-4">
              {showTimeline.suits.map((suit, i) => {
                const suitTypes: Record<string, string> = { full_suit: isUrdu ? 'فل سوٹ' : 'Full Suit', kameez: isUrdu ? 'قمیض' : 'Kameez', shalwar: isUrdu ? 'شلوار' : 'Shalwar' };
                const assignedWorkers = suit.workers ? Object.entries(suit.workers).map(([status, id]) => ({
                  status, worker: data.workers.find(w => w.id === id)
                })).filter(aw => aw.worker) : [];
                return (
                  <div key={suit.id} className="bg-background rounded-xl p-4 border border-border">
                    <div className="flex items-center justify-between mb-2">
                      <h3 className="font-semibold text-sm">{isUrdu ? 'سوٹ' : 'Suit'} #{i + 1} — {suitTypes[suit.type]}</h3>
                      <StatusBadge status={suit.status} />
                    </div>
                    {assignedWorkers.length > 0 && (
                      <div className="flex flex-wrap gap-1.5 mb-2">
                        {assignedWorkers.map(aw => (
                          <span key={aw.status} className="text-[9px] bg-muted px-2 py-0.5 rounded text-muted-foreground">
                            {t(`status.${aw.status}`)}: <span className="font-semibold">{aw.worker!.name}</span>
                          </span>
                        ))}
                      </div>
                    )}
                    {suit.location && (suit.location.box || suit.location.line || suit.location.khanna) && (
                      <div className="flex items-center gap-2 text-[10px] text-muted-foreground mb-2 bg-muted/50 rounded-lg px-2 py-1">
                        <MapPin size={10} />
                        {suit.location.box && <span>{isUrdu ? 'باکس' : 'Box'}: {suit.location.box}</span>}
                        {suit.location.line && <span>{isUrdu ? 'لائن' : 'Line'}: {suit.location.line}</span>}
                        {suit.location.khanna && <span>{isUrdu ? 'خانہ' : 'Khanna'}: {suit.location.khanna}</span>}
                      </div>
                    )}
                    <SuitTimeline suit={suit} t={t} isUrdu={isUrdu} />
                  </div>
                );
              })}
              {showTimeline.deliveredAt && (
                <div className="bg-success/5 border border-success/20 rounded-xl p-4 text-center">
                  <p className="text-sm font-semibold text-success">🤝 {isUrdu ? 'حوالے کیا گیا' : 'Delivered'}</p>
                  <p className="text-xs text-muted-foreground">{new Date(showTimeline.deliveredAt).toLocaleString()}</p>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Order Form Modal */}
      {showForm && (
        <div className="fixed inset-0 z-50 bg-foreground/40 flex items-end sm:items-center justify-center" onClick={() => setShowForm(false)}>
          <div className="premium-card w-full max-w-lg rounded-t-2xl sm:rounded-2xl max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
            <div className="flex items-center justify-between p-4 border-b border-border sticky top-0 bg-card z-10">
              <h2 className="font-bold text-lg">{editingOrder ? t('common.edit') : t('order.new')}</h2>
              <button onClick={() => setShowForm(false)} className="p-2 touch-target"><X size={20} /></button>
            </div>
            <div className="p-4 space-y-4">
              <div>
                <label className="text-xs text-muted-foreground font-medium">{t('nav.customers')} *</label>
                <select value={customerId} onChange={e => setCustomerId(e.target.value)} className="w-full px-4 py-3 rounded-xl bg-background border border-border text-sm focus:outline-none focus:ring-2 focus:ring-primary/30 touch-target">
                  {data.customers.map(c => (
                    <option key={c.id} value={c.id}>{c.name} ({c.customerId})</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="text-xs text-muted-foreground font-medium">{t('order.delivery')} *</label>
                <input type="date" value={deadline} onChange={e => setDeadline(e.target.value)} className="w-full px-4 py-3 rounded-xl bg-background border border-border text-sm focus:outline-none focus:ring-2 focus:ring-primary/30 touch-target" />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-xs text-muted-foreground font-medium">{t('common.total')} (Rs)</label>
                  <input type="number" value={totalAmount} onChange={e => setTotalAmount(e.target.value)} className="w-full px-4 py-3 rounded-xl bg-background border border-border text-sm focus:outline-none focus:ring-2 focus:ring-primary/30 touch-target" />
                </div>
                <div>
                  <label className="text-xs text-muted-foreground font-medium">{t('common.advance')} (Rs)</label>
                  <input type="number" value={advancePaid} onChange={e => setAdvancePaid(e.target.value)} className="w-full px-4 py-3 rounded-xl bg-background border border-border text-sm focus:outline-none focus:ring-2 focus:ring-primary/30 touch-target" />
                </div>
              </div>
              <div>
                <div className="flex items-center justify-between mb-2">
                  <h3 className="font-semibold text-sm">{t('order.suits')}</h3>
                  <button onClick={addSuit} className="text-xs text-primary font-semibold px-3 py-1 rounded-lg bg-primary/10 touch-target">+ {isUrdu ? 'سوٹ شامل کریں' : 'Add Suit'}</button>
                </div>
                <div className="space-y-3">
                  {suits.map((suit, idx) => (
                    <div key={suit.id} className="bg-background rounded-xl p-3 border border-border space-y-2">
                      <div className="flex items-center justify-between">
                        <span className="text-xs font-semibold">{isUrdu ? 'سوٹ' : 'Suit'} #{idx + 1}</span>
                        {suits.length > 1 && (
                          <button onClick={() => removeSuit(idx)} className="text-destructive text-xs">{isUrdu ? 'ہٹائیں' : 'Remove'}</button>
                        )}
                      </div>
                      <select value={suit.type} onChange={e => updateSuit(idx, { type: e.target.value as any })} className="w-full px-3 py-2 rounded-lg bg-card border border-border text-sm">
                        <option value="full_suit">{isUrdu ? 'فل سوٹ' : 'Full Suit'}</option>
                        <option value="kameez">{isUrdu ? 'صرف قمیض' : 'Kameez Only'}</option>
                        <option value="shalwar">{isUrdu ? 'صرف شلوار' : 'Shalwar Only'}</option>
                      </select>
                      <div className="space-y-2 rounded-lg border border-border/60 bg-card p-3">
                        <div className="flex items-center justify-between gap-2">
                          <span className="text-xs font-semibold text-muted-foreground">{isUrdu ? 'مرحلہ وار کاریگر' : 'Stage-wise Worker Assignment'}</span>
                          <span className="text-[10px] text-primary font-semibold">{t(`status.${suit.status}`)}</span>
                        </div>
                        <div className="grid grid-cols-2 gap-2">
                          {(['cutting', 'stitching', 'finishing', 'packed', 'ready'] as SuitStatus[]).map(stage => (
                            <div key={stage} className="space-y-1">
                              <label className="text-[10px] text-muted-foreground">{t(`status.${stage}`)}</label>
                              <select
                                value={suit.workers?.[stage] || ''}
                                onChange={e => {
                                  const newWorkers = { ...(suit.workers || {}) };
                                  if (e.target.value) newWorkers[stage] = e.target.value;
                                  else delete newWorkers[stage];
                                  updateSuit(idx, {
                                    workers: Object.keys(newWorkers).length ? newWorkers : undefined,
                                    workerId: stage === suit.status ? (e.target.value || undefined) : suit.workerId,
                                  });
                                }}
                                className="w-full px-3 py-2 rounded-lg bg-background border border-border text-xs"
                              >
                                <option value="">{isUrdu ? 'کوئی نہیں' : 'Unassigned'}</option>
                                {data.workers.filter(w => w.active).map(w => (
                                  <option key={w.id} value={w.id}>{w.name}</option>
                                ))}
                              </select>
                            </div>
                          ))}
                        </div>
                      </div>
                      <label className="flex items-center gap-2 text-sm">
                        <input type="checkbox" checked={suit.designWork} onChange={e => updateSuit(idx, { designWork: e.target.checked })} className="rounded" />
                        {isUrdu ? 'ڈیزائن ورک' : 'Design Work'}
                      </label>
                      {editingOrder && (
                        <select value={suit.status} onChange={e => { const nextStatus = e.target.value as SuitStatus; updateSuit(idx, { status: nextStatus, workerId: suit.workers?.[nextStatus] }); }} className="w-full px-3 py-2 rounded-lg bg-card border border-border text-sm">
                          {ALL_STATUSES.map(s => (
                            <option key={s} value={s}>{t(`status.${s}`)}</option>
                          ))}
                        </select>
                      )}
                      {/* Location tracking */}
                      <div className="pt-1 border-t border-border/50">
                        <p className="text-[10px] font-semibold text-muted-foreground mb-1 flex items-center gap-1">
                          <MapPin size={10} /> {isUrdu ? 'جگہ / مقام' : 'Storage Location'}
                        </p>
                        <div className="grid grid-cols-3 gap-2">
                          <input
                            type="text"
                            value={suit.location?.box || ''}
                            onChange={e => updateSuit(idx, { location: { ...(suit.location || { box: '', line: '', khanna: '' }), box: e.target.value } })}
                            placeholder={isUrdu ? 'باکس #' : 'Box #'}
                            className="px-2 py-1.5 rounded-lg bg-card border border-border text-xs focus:outline-none focus:ring-2 focus:ring-primary/30"
                          />
                          <input
                            type="text"
                            value={suit.location?.line || ''}
                            onChange={e => updateSuit(idx, { location: { ...(suit.location || { box: '', line: '', khanna: '' }), line: e.target.value } })}
                            placeholder={isUrdu ? 'لائن #' : 'Line #'}
                            className="px-2 py-1.5 rounded-lg bg-card border border-border text-xs focus:outline-none focus:ring-2 focus:ring-primary/30"
                          />
                          <input
                            type="text"
                            value={suit.location?.khanna || ''}
                            onChange={e => updateSuit(idx, { location: { ...(suit.location || { box: '', line: '', khanna: '' }), khanna: e.target.value } })}
                            placeholder={isUrdu ? 'خانہ #' : 'Khanna #'}
                            className="px-2 py-1.5 rounded-lg bg-card border border-border text-xs focus:outline-none focus:ring-2 focus:ring-primary/30"
                          />
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
              <div>
                <label className="text-xs text-muted-foreground font-medium">{isUrdu ? 'نوٹس' : 'Notes'}</label>
                <VoiceInput value={notes} onChange={setNotes} multiline rows={2} placeholder={isUrdu ? 'آرڈر کے بارے میں نوٹس...' : 'Order notes...'} append />
              </div>
              <div className="flex gap-3 pt-2">
                {editingOrder && (
                  <button onClick={() => { deleteOrder(editingOrder.id); setShowForm(false); }} className="flex-1 py-3 rounded-xl border border-destructive text-destructive font-semibold touch-target active:scale-95">
                    {t('common.delete')}
                  </button>
                )}
                <button onClick={handleSave} className="flex-1 py-3 bg-primary text-primary-foreground rounded-xl font-semibold touch-target active:scale-95 transition-transform">
                  {t('common.save')}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { useLang } from '@/contexts/LanguageContext';
import { useData } from '@/contexts/DataContext';
import { generateId } from '@/lib/store';
import type { PaymentRecord } from '@/lib/store';
import SearchBar from '@/components/SearchBar';
import { DollarSign, Check, X, Clock, CreditCard, Banknote, History } from 'lucide-react';

type Tab = 'pending' | 'paid' | 'history';

export default function Payments() {
  const { t, isUrdu } = useLang();
  const { data, updateOrder } = useData();
  const [search, setSearch] = useState('');
  const [tab, setTab] = useState<Tab>('pending');
  const [payModal, setPayModal] = useState<string | null>(null);
  const [payAmount, setPayAmount] = useState('');
  const [payMethod, setPayMethod] = useState<PaymentRecord['method']>('cash');
  const [payNote, setPayNote] = useState('');

  const pendingOrders = data.orders
    .filter(o => o.paymentStatus !== 'paid')
    .sort((a, b) => (b.totalAmount - b.advancePaid) - (a.totalAmount - a.advancePaid));

  const paidOrders = data.orders
    .filter(o => o.paymentStatus === 'paid')
    .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());

  const allPayments = data.orders
    .flatMap(o => (o.paymentHistory || []).map(p => ({
      ...p,
      orderId: o.id,
      customerId: o.customerId,
      orderTotal: o.totalAmount,
    })))
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const filterBySearch = (customerId: string) => {
    if (!search) return true;
    const customer = data.customers.find(c => c.id === customerId);
    if (!customer) return false;
    const q = search.toLowerCase();
    return customer.name.toLowerCase().includes(q) || customer.customerId.toLowerCase().includes(q) || customer.phone.includes(q);
  };

  const totalPending = pendingOrders.reduce((sum, o) => sum + (o.totalAmount - o.advancePaid), 0);
  const totalCollected = data.orders.reduce((sum, o) => sum + o.advancePaid, 0);

  const handlePay = () => {
    if (!payModal || !payAmount) return;
    const order = data.orders.find(o => o.id === payModal);
    if (!order) return;
    const amount = Math.min(Number(payAmount) || 0, order.totalAmount - order.advancePaid);
    if (amount <= 0) return;

    const record: PaymentRecord = {
      id: generateId(),
      amount,
      date: new Date().toISOString(),
      method: payMethod,
      note: payNote,
    };

    const newAdvance = order.advancePaid + amount;
    const status = newAdvance >= order.totalAmount ? 'paid' : newAdvance > 0 ? 'partial' : 'pending';
    const history = [...(order.paymentHistory || []), record];

    updateOrder(payModal, {
      advancePaid: Math.min(newAdvance, order.totalAmount),
      paymentStatus: status as any,
      paymentHistory: history,
    });
    setPayModal(null);
    setPayAmount('');
    setPayNote('');
    setPayMethod('cash');
  };

  const deletePaymentRecord = (orderId: string, recordId: string) => {
    const order = data.orders.find(o => o.id === orderId);
    if (!order) return;
    const record = (order.paymentHistory || []).find(p => p.id === recordId);
    if (!record) return;
    const newHistory = (order.paymentHistory || []).filter(p => p.id !== recordId);
    const newAdvance = Math.max(0, order.advancePaid - record.amount);
    const status = newAdvance >= order.totalAmount ? 'paid' : newAdvance > 0 ? 'partial' : 'pending';
    updateOrder(orderId, { advancePaid: newAdvance, paymentStatus: status as any, paymentHistory: newHistory });
  };

  const methodLabel = (m: string) => {
    const labels: Record<string, string> = {
      cash: isUrdu ? 'نقد' : 'Cash',
      bank: isUrdu ? 'بینک' : 'Bank',
      easypaisa: 'Easypaisa',
      jazzcash: 'JazzCash',
      other: isUrdu ? 'دیگر' : 'Other',
    };
    return labels[m] || m;
  };

  const methodIcon: Record<string, string> = { cash: '💵', bank: '🏦', easypaisa: '📱', jazzcash: '📱', other: '💳' };

  return (
    <div className="space-y-4 pb-4">
      <div className="flex items-center gap-2 mb-1">
        <DollarSign size={22} className="text-primary" />
        <h2 className="text-lg font-bold">{isUrdu ? 'ادائیگیاں' : 'Payments'}</h2>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-2 gap-3">
        <div className="bg-destructive/5 border border-destructive/20 rounded-xl p-4 text-center">
          <p className="text-2xl font-bold text-destructive">Rs {totalPending.toLocaleString()}</p>
          <p className="text-xs text-muted-foreground">{isUrdu ? 'بقایا' : 'Pending'}</p>
        </div>
        <div className="bg-success/5 border border-success/20 rounded-xl p-4 text-center">
          <p className="text-2xl font-bold text-success">Rs {totalCollected.toLocaleString()}</p>
          <p className="text-xs text-muted-foreground">{isUrdu ? 'وصول شدہ' : 'Collected'}</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-2">
        {([
          ['pending', isUrdu ? 'بقایا' : 'Pending', pendingOrders.length],
          ['paid', isUrdu ? 'مکمل' : 'Paid', paidOrders.length],
          ['history', isUrdu ? 'تاریخ' : 'History', allPayments.length],
        ] as const).map(([key, label, count]) => (
          <button key={key} onClick={() => setTab(key as Tab)}
            className={`flex-1 py-2 rounded-xl text-xs font-semibold transition-colors ${tab === key ? 'bg-primary text-primary-foreground' : 'bg-muted text-muted-foreground'}`}>
            {label} <span className="opacity-70">({count})</span>
          </button>
        ))}
      </div>

      <SearchBar value={search} onChange={setSearch} />

      {/* Pending Tab */}
      {tab === 'pending' && (
        <div className="space-y-2">
          {pendingOrders.filter(o => filterBySearch(o.customerId)).map(order => {
            const customer = data.customers.find(c => c.id === order.customerId);
            const balance = order.totalAmount - order.advancePaid;
            const paidPercent = order.totalAmount > 0 ? Math.round((order.advancePaid / order.totalAmount) * 100) : 0;
            return (
              <div key={order.id} className="bg-card rounded-xl p-4 border border-border space-y-3">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="font-semibold text-sm">{customer?.name}</p>
                    <p className="text-xs text-muted-foreground font-mono">{customer?.customerId}</p>
                  </div>
                  <span className={`text-xs font-bold px-2 py-1 rounded-full ${
                    order.paymentStatus === 'pending' ? 'bg-destructive/10 text-destructive' :
                    order.paymentStatus === 'advance' ? 'bg-warning/10 text-warning' :
                    'bg-accent/10 text-accent-foreground'
                  }`}>
                    {order.paymentStatus === 'pending' ? (isUrdu ? 'بقایا' : 'Pending') :
                     order.paymentStatus === 'advance' ? (isUrdu ? 'پیشگی' : 'Advance') :
                     (isUrdu ? 'جزوی' : 'Partial')}
                  </span>
                </div>
                <div className="space-y-1">
                  <div className="flex justify-between text-xs text-muted-foreground">
                    <span>{isUrdu ? 'کل' : 'Total'}: Rs {order.totalAmount.toLocaleString()}</span>
                    <span>{isUrdu ? 'وصول' : 'Paid'}: Rs {order.advancePaid.toLocaleString()}</span>
                  </div>
                  {/* Progress bar */}
                  <div className="w-full h-2 bg-muted rounded-full overflow-hidden">
                    <div className="h-full bg-primary rounded-full transition-all" style={{ width: `${paidPercent}%` }} />
                  </div>
                  <div className="flex justify-between text-xs">
                    <span className="text-muted-foreground">{paidPercent}%</span>
                    <span className="font-bold text-destructive">{isUrdu ? 'بقایا' : 'Due'}: Rs {balance.toLocaleString()}</span>
                  </div>
                </div>
                {/* Payment history for this order */}
                {(order.paymentHistory || []).length > 0 && (
                  <div className="space-y-1">
                    {(order.paymentHistory || []).slice(-3).map(p => (
                      <div key={p.id} className="flex items-center justify-between text-[10px] text-muted-foreground">
                        <span>{methodIcon[p.method]} {new Date(p.date).toLocaleDateString()} {p.note && `· ${p.note}`}</span>
                        <span className="font-semibold text-success">+Rs {p.amount.toLocaleString()}</span>
                      </div>
                    ))}
                  </div>
                )}
                <button
                  onClick={() => { setPayModal(order.id); setPayAmount(''); setPayNote(''); setPayMethod('cash'); }}
                  className="w-full py-3 bg-success text-success-foreground rounded-xl font-semibold text-sm touch-target active:scale-95 transition-transform flex items-center justify-center gap-2"
                >
                  <Banknote size={16} /> {isUrdu ? 'ادائیگی وصول کریں' : 'Record Payment'}
                </button>
              </div>
            );
          })}
          {pendingOrders.filter(o => filterBySearch(o.customerId)).length === 0 && (
            <div className="text-center py-8">
              <Check size={40} className="mx-auto text-success mb-2" />
              <p className="text-muted-foreground text-sm">{isUrdu ? 'کوئی بقایا نہیں' : 'No pending payments'}</p>
            </div>
          )}
        </div>
      )}

      {/* Paid Tab */}
      {tab === 'paid' && (
        <div className="space-y-2">
          {paidOrders.filter(o => filterBySearch(o.customerId)).map(order => {
            const customer = data.customers.find(c => c.id === order.customerId);
            return (
              <div key={order.id} className="bg-card rounded-xl p-4 border border-border">
                <div className="flex items-center justify-between mb-1">
                  <div>
                    <p className="font-semibold text-sm">{customer?.name}</p>
                    <p className="text-xs text-muted-foreground font-mono">{customer?.customerId}</p>
                  </div>
                  <span className="text-xs font-bold px-2 py-1 rounded-full bg-success/10 text-success">
                    ✅ {isUrdu ? 'مکمل' : 'Paid'}
                  </span>
                </div>
                <p className="text-sm font-semibold text-success">Rs {order.totalAmount.toLocaleString()}</p>
                <p className="text-[10px] text-muted-foreground">
                  {(order.paymentHistory || []).length} {isUrdu ? 'ادائیگیاں' : 'payments'} · {new Date(order.createdAt).toLocaleDateString()}
                </p>
              </div>
            );
          })}
          {paidOrders.filter(o => filterBySearch(o.customerId)).length === 0 && (
            <p className="text-center text-muted-foreground py-8 text-sm">{isUrdu ? 'کوئی مکمل ادائیگی نہیں' : 'No paid orders'}</p>
          )}
        </div>
      )}

      {/* History Tab */}
      {tab === 'history' && (
        <div className="space-y-2">
          {allPayments.filter(p => filterBySearch(p.customerId)).map(p => {
            const customer = data.customers.find(c => c.id === p.customerId);
            return (
              <div key={p.id} className="bg-card rounded-xl p-3 border border-border flex items-center gap-3">
                <div className="w-8 h-8 rounded-full bg-success/10 flex items-center justify-center text-sm shrink-0">
                  {methodIcon[p.method]}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-semibold">{customer?.name}</p>
                  <p className="text-[10px] text-muted-foreground">
                    {new Date(p.date).toLocaleString()} · {methodLabel(p.method)}
                    {p.note && ` · ${p.note}`}
                  </p>
                </div>
                <div className="text-right shrink-0 flex items-center gap-1">
                  <span className="font-bold text-success text-sm">+Rs {p.amount.toLocaleString()}</span>
                  <button onClick={() => deletePaymentRecord(p.orderId, p.id)}
                    className="text-destructive/50 hover:text-destructive p-1 touch-target"><X size={14} /></button>
                </div>
              </div>
            );
          })}
          {allPayments.filter(p => filterBySearch(p.customerId)).length === 0 && (
            <p className="text-center text-muted-foreground py-8 text-sm">{isUrdu ? 'کوئی ادائیگی نہیں' : 'No payment history'}</p>
          )}
        </div>
      )}

      {/* Payment Modal */}
      {payModal && (
        <div className="fixed inset-0 z-50 bg-foreground/40 flex items-end sm:items-center justify-center" onClick={() => setPayModal(null)}>
          <div className="bg-card w-full max-w-lg rounded-t-2xl sm:rounded-2xl" onClick={e => e.stopPropagation()}>
            <div className="flex items-center justify-between p-4 border-b border-border">
              <h2 className="font-bold text-lg">{isUrdu ? 'ادائیگی وصول کریں' : 'Record Payment'}</h2>
              <button onClick={() => setPayModal(null)} className="p-2 touch-target"><X size={20} /></button>
            </div>
            <div className="p-4 space-y-4">
              {(() => {
                const order = data.orders.find(o => o.id === payModal);
                const customer = order ? data.customers.find(c => c.id === order.customerId) : null;
                const balance = order ? order.totalAmount - order.advancePaid : 0;
                return (
                  <>
                    <div className="bg-background rounded-xl p-3 border border-border">
                      <p className="text-sm font-semibold">{customer?.name}</p>
                      <div className="flex justify-between text-xs text-muted-foreground mt-1">
                        <span>{isUrdu ? 'کل' : 'Total'}: Rs {order?.totalAmount.toLocaleString()}</span>
                        <span>{isUrdu ? 'وصول' : 'Paid'}: Rs {order?.advancePaid.toLocaleString()}</span>
                      </div>
                      <p className="text-sm font-bold text-destructive mt-1">{isUrdu ? 'بقایا' : 'Balance'}: Rs {balance.toLocaleString()}</p>
                    </div>
                    <div>
                      <label className="text-xs text-muted-foreground font-medium">{isUrdu ? 'رقم' : 'Amount'}</label>
                      <input
                        type="number"
                        value={payAmount}
                        onChange={e => setPayAmount(e.target.value)}
                        placeholder={isUrdu ? 'رقم درج کریں' : 'Enter amount'}
                        className="w-full px-4 py-4 rounded-xl bg-background border border-border text-lg font-semibold focus:outline-none focus:ring-2 focus:ring-primary/30 touch-target"
                      />
                    </div>
                    {/* Quick amounts */}
                    <div className="flex gap-2 flex-wrap">
                      <button onClick={() => setPayAmount(String(balance))} className="px-3 py-1.5 rounded-lg bg-muted text-muted-foreground text-xs font-semibold active:scale-95">
                        {isUrdu ? 'پوری رقم' : 'Full'} ({balance.toLocaleString()})
                      </button>
                      {balance > 1000 && (
                        <button onClick={() => setPayAmount(String(Math.round(balance / 2)))} className="px-3 py-1.5 rounded-lg bg-muted text-muted-foreground text-xs font-semibold active:scale-95">
                          {isUrdu ? 'آدھی' : 'Half'} ({Math.round(balance / 2).toLocaleString()})
                        </button>
                      )}
                    </div>
                    {/* Payment method */}
                    <div>
                      <label className="text-xs text-muted-foreground font-medium">{isUrdu ? 'طریقہ' : 'Method'}</label>
                      <div className="flex gap-2 flex-wrap mt-1">
                        {(['cash', 'bank', 'easypaisa', 'jazzcash', 'other'] as const).map(m => (
                          <button key={m} onClick={() => setPayMethod(m)}
                            className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-colors ${payMethod === m ? 'bg-primary text-primary-foreground' : 'bg-muted text-muted-foreground'}`}>
                            {methodIcon[m]} {methodLabel(m)}
                          </button>
                        ))}
                      </div>
                    </div>
                    <div>
                      <label className="text-xs text-muted-foreground font-medium">{isUrdu ? 'نوٹ' : 'Note'}</label>
                      <input value={payNote} onChange={e => setPayNote(e.target.value)} placeholder={isUrdu ? 'اختیاری...' : 'Optional...'}
                        className="w-full px-4 py-3 rounded-xl bg-background border border-border text-sm focus:outline-none focus:ring-2 focus:ring-primary/30 touch-target" />
                    </div>
                    <button onClick={handlePay} className="w-full py-4 bg-success text-success-foreground rounded-xl font-semibold text-base touch-target active:scale-95 transition-transform flex items-center justify-center gap-2">
                      <Check size={18} /> {isUrdu ? 'ادائیگی محفوظ کریں' : 'Save Payment'}
                    </button>
                  </>
                );
              })()}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import type { Config } from "tailwindcss";

export default {
  darkMode: ["class"],
  content: ["./pages/**/*.{ts,tsx}", "./components/**/*.{ts,tsx}", "./app/**/*.{ts,tsx}", "./src/**/*.{ts,tsx}"],
  prefix: "",
  theme: {
    container: {
      center: true,
      padding: "1rem",
      screens: {
        "2xl": "1400px",
      },
    },
    extend: {
      fontFamily: {
        sans: ["Inter", "system-ui", "sans-serif"],
        urdu: ["'Noto Nastaliq Urdu'", "serif"],
      },
      colors: {
        border: "hsl(var(--border))",
        input: "hsl(var(--input))",
        ring: "hsl(var(--ring))",
        background: "hsl(var(--background))",
        foreground: "hsl(var(--foreground))",
        primary: {
          DEFAULT: "hsl(var(--primary))",
          foreground: "hsl(var(--primary-foreground))",
        },
        secondary: {
          DEFAULT: "hsl(var(--secondary))",
          foreground: "hsl(var(--secondary-foreground))",
